function parseInventoryApprovalNotificationTxnId(row: Pick<MaintenanceNotification, "kind" | "key">) {
  if (String(row.kind || "") !== "inventory_out_approval") return 0;
  const match = String(row.key || "").match(/^inventory-out-approval:(\d+)$/);
  return match ? Number(match[1]) || 0 : 0;
}

function normalizePopupSortCellText(value: string) {
  return String(value || "").replace(/\s+/g, " ").trim();
}

function parsePopupSortCellValue(value: string) {
  const raw = normalizePopupSortCellText(value);
  if (!raw) return { kind: "text" as const, value: "" };

  const numericRaw = raw.replace(/,/g, "");
  if (/^-?\d+(\.\d+)?$/.test(numericRaw)) {
    return { kind: "number" as const, value: Number(numericRaw) };
  }

  const isLikelyDate =
    /^\d{4}-\d{2}-\d{2}/.test(raw) ||
    /^\d{4}-[A-Za-z]{3}-\d{2}/.test(raw) ||
    /^\d{1,2}[/-]\d{1,2}[/-]\d{2,4}/.test(raw) ||
    /^[A-Za-z]{3,9}\s+\d{1,2},\s*\d{4}/.test(raw);
  if (isLikelyDate) {
    const parsedMs = Date.parse(raw.replace(/-/g, " "));
    if (Number.isFinite(parsedMs)) {
      return { kind: "date" as const, value: parsedMs };
    }
  }

  return { kind: "text" as const, value: raw.toLowerCase() };
}

function comparePopupSortCellValues(aRaw: string, bRaw: string) {
  const a = parsePopupSortCellValue(aRaw);
  const b = parsePopupSortCellValue(bRaw);
  if (a.kind === b.kind) {
    if (a.kind === "number" || a.kind === "date") {
      return Number(a.value) - Number(b.value);
    }
    return String(a.value).localeCompare(String(b.value), undefined, { numeric: true, sensitivity: "base" });
  }
  return normalizePopupSortCellText(aRaw).localeCompare(normalizePopupSortCellText(bRaw), undefined, {
    numeric: true,
    sensitivity: "base",
  });
}

function formatNumericInputDisplay(value: string) {
  const raw = String(value || "").replace(/[^0-9.,]/g, "").replace(/,/g, "");
  if (!raw) return "";
  const hasDecimal = raw.includes(".");
  const [intPartRaw, decimalPartRaw = ""] = raw.split(".");
  const intPart = intPartRaw.replace(/^0+(?=\d)/, "") || "0";
  const formattedInt = intPart.replace(/\B(?=(\d{3})+(?!\d))/g, ",");
  if (!hasDecimal) return formattedInt;
  return `${formattedInt}.${decimalPartRaw.replace(/\./g, "")}`;
}

function formatRielAmount(value: unknown) {
  const amount = Number(value);
  if (!Number.isFinite(amount) || amount <= 0) return "-";
  return `${formatNumericInputDisplay(String(amount))} Riel`;
}

function formatCompactRiel(value: unknown) {
  const amount = Number(value);
  if (!Number.isFinite(amount) || amount <= 0) return "-";
  if (amount >= 1000000) return `R ${formatNumericInputDisplay((amount / 1000000).toFixed(2))}M`;
  if (amount >= 1000) return `R ${formatNumericInputDisplay((amount / 1000).toFixed(0))}K`;
  return `R ${formatNumericInputDisplay(String(amount))}`;
}

function monthShortLabel(value: string) {
  if (!value) return value;
  const normalized = /^\d{4}-\d{2}$/.test(value) ? `${value}-01` : value;
  const date = new Date(normalized);
  if (Number.isNaN(date.getTime())) return value;
  return date.toLocaleString("en-US", { month: "short" });
}

const UTILITY_C22_SITE_OPTIONS = ["#63 (32P)", "#65 (63P)"] as const;

function normalizeInventoryApprovalCampusValue(value: unknown) {
  const raw = String(value || "").trim();
  if (!raw) return "";
  if (CAMPUS_LIST.includes(raw)) return raw;
  const upper = raw.toUpperCase();
  if (upper === "ALL") return "";
  return CODE_TO_CAMPUS[raw] || CODE_TO_CAMPUS[upper] || "";
}
function normalizeInventoryApprovalRoutingMap(input: unknown): InventoryApprovalRoutingMap {
  if (!input || typeof input !== "object" || Array.isArray(input)) return {};
  const out: InventoryApprovalRoutingMap = {};
  for (const [rawRequester, rawApprovers] of Object.entries(input as Record<string, unknown>)) {
    const requester = String(rawRequester || "").trim().toLowerCase();
    if (!requester) continue;
    const approverRows = Array.isArray(rawApprovers)
      ? rawApprovers
      : (rawApprovers && typeof rawApprovers === "object" && !Array.isArray(rawApprovers))
        ? (Array.isArray((rawApprovers as { approvers?: unknown }).approvers) ? (rawApprovers as { approvers: unknown[] }).approvers : [])
        : [];
    const campus = Array.isArray(rawApprovers)
      ? ""
      : (rawApprovers && typeof rawApprovers === "object" && !Array.isArray(rawApprovers))
        ? normalizeInventoryApprovalCampusValue((rawApprovers as { campus?: unknown }).campus)
        : "";
    const approvers = Array.from(
      new Set(
        approverRows
          .map((value) => String(value || "").trim().toLowerCase())
          .filter(Boolean)
      )
    );
    out[requester] = { campus, approvers };
  }
  return out;
}
