type SetPackChildType = "MON" | "MON2" | "KBD" | "MSE" | "UWF" | "WBC";
type LaptopAccessoryType = "ADP" | "MSE" | "KBD" | "MON";
type CameraComponentType = "BAT" | "CHB" | "MCD" | "BAG";
type ProjectorComponentType = "PBG" | "RMT" | "ADP" | "HDC";
type SetPackChildDraft = {
  enabled: boolean;
  status: string;
  brand: string;
  model: string;
  serialNumber: string;
  purchaseDate: string;
  warrantyUntil: string;
  vendor: string;
  specs: string;
  notes: string;
  photo: string;
  photos: string[];
};

function defaultSetPackChildDraft(): SetPackChildDraft {
  return {
    enabled: true,
    status: "Active",
    brand: "",
    model: "",
    serialNumber: "",
    purchaseDate: "",
    warrantyUntil: "",
    vendor: "",
    specs: "",
    notes: "",
    photo: "",
    photos: [],
  };
}

function defaultSetPackDraft(): Record<SetPackChildType, SetPackChildDraft> {
  return {
    MON: defaultSetPackChildDraft(),
    MON2: { ...defaultSetPackChildDraft(), enabled: false },
    KBD: defaultSetPackChildDraft(),
    MSE: defaultSetPackChildDraft(),
    UWF: { ...defaultSetPackChildDraft(), enabled: false },
    WBC: { ...defaultSetPackChildDraft(), enabled: false },
  };
}

function defaultLaptopAccessoryDraft(): Record<LaptopAccessoryType, SetPackChildDraft> {
  return {
    ADP: defaultSetPackChildDraft(),
    MSE: defaultSetPackChildDraft(),
    KBD: defaultSetPackChildDraft(),
    MON: defaultSetPackChildDraft(),
  };
}

function defaultCameraComponentDraft(): Record<CameraComponentType, SetPackChildDraft> {
  return {
    BAT: defaultSetPackChildDraft(),
    CHB: defaultSetPackChildDraft(),
    MCD: defaultSetPackChildDraft(),
    BAG: defaultSetPackChildDraft(),
  };
}

function defaultProjectorComponentDraft(): Record<ProjectorComponentType, SetPackChildDraft> {
  return {
    PBG: defaultSetPackChildDraft(),
    RMT: defaultSetPackChildDraft(),
    ADP: defaultSetPackChildDraft(),
    HDC: defaultSetPackChildDraft(),
  };
}

function setPackAssetType(type: SetPackChildType): "MON" | "KBD" | "MSE" | "UWF" | "WBC" {
  if (type === "MON2") return "MON";
  return type;
}

function canLinkToParentAsset(category: string, type: string): boolean {
  const normalizedCategory = String(category || "").trim().toUpperCase();
  if (normalizedCategory === "SAFETY") return false;
  const code = String(type || "").trim().toUpperCase();
  return (
    !NO_PARENT_LINK_TYPES.has(code) &&
    !DIGITAL_CAMERA_COMPONENT_TYPES.includes(code as (typeof DIGITAL_CAMERA_COMPONENT_TYPES)[number]) &&
    code !== WATER_DISPENSER_MAIN_TYPE &&
    code !== "AC" &&
    code !== "WTK" &&
    code !== "TBL" &&
    code !== "CHR" &&
    code !== "NBD"
  );
}

function isSingleFurnitureType(type: string): boolean {
  return String(type || "").trim().toUpperCase() === "NBD";
}

function needsComponentRole(type: string): boolean {
  return String(type || "").trim().toUpperCase() !== WEBCAM_TYPE_CODE;
}

