function clearAllFallbackCaches() {
  const keys = [
    LOCATION_FALLBACK_KEY,
    ASSET_FALLBACK_KEY,
    USER_FALLBACK_KEY,
    CAMPUS_NAME_FALLBACK_KEY,
    ITEM_NAME_FALLBACK_KEY,
    ITEM_TYPE_FALLBACK_KEY,
    ITEM_TEMPLATE_FALLBACK_KEY,
    AUTH_PERMISSION_FALLBACK_KEY,
    AUTH_ACCOUNTS_FALLBACK_KEY,
    AUDIT_FALLBACK_KEY,
    INVENTORY_ITEM_FALLBACK_KEY,
    INVENTORY_TXN_FALLBACK_KEY,
    POOL_CLEANING_SCHEDULE_FALLBACK_KEY,
    POOL_EQUIPMENT_FALLBACK_KEY,
    POOL_CHEMICAL_FALLBACK_KEY,
    POOL_OPERATION_FALLBACK_KEY,
    POOL_COMPLAINT_FALLBACK_KEY,
    UTILITY_METER_FALLBACK_KEY,
    UTILITY_READING_FALLBACK_KEY,
    VAULT_ACCOUNTS_FALLBACK_KEY,
    VAULT_CREDENTIALS_FALLBACK_KEY,
    VAULT_DESIGN_LINKS_FALLBACK_KEY,
    VAULT_NETWORK_DOCS_FALLBACK_KEY,
    VAULT_CCTV_FALLBACK_KEY,
  ];
  for (const key of keys) {
    try {
      localStorage.removeItem(key);
    } catch {
      // Ignore storage errors.
    }
  }
}

