function sortLocationEntriesByName(rows: LocationEntry[]) {
  return [...rows].sort((a, b) =>
    a.name.localeCompare(b.name, undefined, { sensitivity: "base", numeric: true })
  );
}

function mergeLocations(primary: LocationEntry[], secondary: LocationEntry[]) {
  const out = new Map<string, LocationEntry>();

  for (const loc of [...secondary, ...primary]) {
    const key = `${loc.campus.toLowerCase()}::${loc.name.toLowerCase()}`;
    const current = out.get(key);
    out.set(key, {
      ...(current || {}),
      ...loc,
      isClassroom: isClassroomLocationLike({
        isClassroom: loc.isClassroom ?? current?.isClassroom,
        currentStudents: loc.currentStudents ?? current?.currentStudents,
        name: loc.name ?? current?.name,
      }),
      studentCapacity: Math.max(0, Number(loc.studentCapacity ?? current?.studentCapacity) || 0),
      currentStudents: Math.max(0, Number(loc.currentStudents ?? current?.currentStudents) || 0),
      tableSeatsPerTable: Math.max(1, Number(loc.tableSeatsPerTable ?? current?.tableSeatsPerTable) || 2),
      notes: String(loc.notes ?? current?.notes ?? "").trim(),
      photo: String(loc.photo ?? current?.photo ?? "").trim(),
    });
  }
  return Array.from(out.values());
}

function isMissingRouteError(err: unknown) {
  return err instanceof Error && err.message.toLowerCase().includes("route not found");
}

function isApiUnavailableError(err: unknown) {
  if (!(err instanceof Error)) return false;
  const m = err.message.toLowerCase();
  return m.includes("route not found") || m.includes("cannot connect to api server");
}

function isUnauthorizedError(err: unknown) {
  if (!(err instanceof Error)) return false;
  const m = err.message.toLowerCase();
  return m.includes("unauthorized") || m.includes("request failed (401)") || m.includes("request failed (403)");
}

function isHistoryRecordNotFoundError(err: unknown) {
  if (!(err instanceof Error)) return false;
  const message = err.message.toLowerCase();
  return message.includes("history record not found") || message.includes("status history record not found");
}

function formatDate(value: string) {
  if (!value || value === "-") return "-";
  const date = new Date(value);
  if (Number.isNaN(date.getTime())) return value;
  const day = String(date.getDate()).padStart(2, "0");
  const month = date.toLocaleString("en-US", { month: "short" });
  const year = date.getFullYear();
  return `${day}-${month}-${year}`;
}

function formatMonthYear(value: string) {
  if (!value || value === "-") return "-";
  const normalized = /^\d{4}-\d{2}$/.test(value) ? `${value}-01` : value;
  const date = new Date(normalized);
  if (Number.isNaN(date.getTime())) return value;
  const month = date.toLocaleString("en-US", { month: "short" });
  const year = date.getFullYear();
  return `${month}-${year}`;
}

function formatReportSlashLongDate(value: string | Date) {
  const date = value instanceof Date ? value : new Date(value);
  if (Number.isNaN(date.getTime())) return typeof value === "string" ? value : "-";
  const day = String(date.getDate()).padStart(2, "0");
  const month = date.toLocaleDateString("en-US", { month: "long" });
  const year = date.getFullYear();
  return `${day}/${month}/${year}`;
}

function formatDateTime(value: string) {
  if (!value || value === "-") return "-";
  const date = new Date(value);
  if (Number.isNaN(date.getTime())) return value;
  const datePart = formatDate(value);
  const timePart = date.toLocaleTimeString("en-US", {
    hour: "2-digit",
    minute: "2-digit",
  });
  return `${datePart} ${timePart}`;
}

function formatTimeOnly(value: string) {
  if (!value || value === "-") return "-";
  const date = new Date(value);
  if (Number.isNaN(date.getTime())) return "-";
  return date.toLocaleTimeString("en-US", {
    hour: "2-digit",
    minute: "2-digit",
  });
}

function getTermRange(year: number, term: "Term 1" | "Term 2" | "Term 3") {
  if (term === "Term 1") return { from: `${year}-01-01`, to: `${year}-04-30` };
  if (term === "Term 2") return { from: `${year}-05-01`, to: `${year}-08-31` };
  return { from: `${year}-09-01`, to: `${year}-12-31` };
}

function categoryCode(category: string) {
  if (category === "IT") return "COM";
  if (category === "SAFETY") return "EE";
  if (category === "FACILITY") return "FFE";
  if (category === "FURNITURE") return "FFE";
  return "OTA";
}
function assetIdCampusCode(campus: string) {
  const raw = String(CAMPUS_CODE[campus] || campus || "").trim().toUpperCase();
  if (/^ECO\d+$/.test(raw)) return raw;
  const match = raw.match(/^C(\d+)(?:\.\d+)?$/);
  if (match) return `ECO${match[1]}`;
  return "ECOX";
}
function inventoryCategoryCode(category: "SUPPLY" | "CLEAN_TOOL" | "MAINT_TOOL") {
  if (category === "CLEAN_TOOL") return "CT";
  if (category === "MAINT_TOOL") return "MT";
  return "CS";
}
function inventoryRecordCampusCode(campus: string) {
  if (campus === "Chaktomuk Campus" || campus === "Chaktomuk Campus (C2.2)") return "C2";
  return CAMPUS_CODE[campus] || "CX";
}
function isInventoryTxnIn(type: InventoryTxn["type"]) {
  return type === "IN" || type === "BORROW_IN";
}
function isInventoryTxnOut(type: InventoryTxn["type"]) {
  return type === "OUT" || type === "BORROW_OUT" || type === "BORROW_CONSUME";
}
function isInventoryTxnSet(type: InventoryTxn["type"]) {
  return type === "SET";
}
function isInventoryTxnUsageOut(type: InventoryTxn["type"]) {
  return type === "OUT" || type === "BORROW_CONSUME";
}
function isPrinterAssetRow(asset: Pick<Asset, "type"> | Pick<PublicQrAsset, "type"> | null | undefined) {
  return String(asset?.type || "").trim().toUpperCase() === "PRN";
}
function isTonerInventoryItemRow(item: Pick<InventoryItem, "itemGroup"> | null | undefined) {
  return String(item?.itemGroup || "").trim().toUpperCase() === "TONER";
}
type InventoryBusinessGroup = "SUPPLY" | "CLEAN_TOOL" | "MAINT_TOOL" | "TONER";
const INVENTORY_DASHBOARD_GROUP_ORDER: InventoryBusinessGroup[] = ["SUPPLY", "CLEAN_TOOL", "MAINT_TOOL", "TONER"];
const INVENTORY_OPERATIONAL_GROUP_ORDER: Array<"SUPPLY" | "CLEAN_TOOL" | "MAINT_TOOL"> = ["SUPPLY", "CLEAN_TOOL", "MAINT_TOOL"];
function inventoryBusinessGroupValue(
  item: Pick<InventoryItem, "category" | "itemGroup"> | null | undefined
): InventoryBusinessGroup {
  if (isTonerInventoryItemRow(item)) return "TONER";
  const category = String(item?.category || "").trim().toUpperCase();
  if (category === "CLEAN_TOOL") return "CLEAN_TOOL";
  if (category === "MAINT_TOOL") return "MAINT_TOOL";
  return "SUPPLY";
}
function inventoryBusinessGroupLabel(value: InventoryBusinessGroup) {
  if (value === "TONER") return "Printer Toner";
  return INVENTORY_CATEGORY_OPTIONS.find((option) => option.value === value)?.label || "Cleaning Supplies";
}
function inventoryBusinessGroupThemeClass(value: InventoryBusinessGroup) {
  if (value === "SUPPLY") return "inventory-theme-supply";
  if (value === "CLEAN_TOOL") return "inventory-theme-clean-tool";
  if (value === "MAINT_TOOL") return "inventory-theme-maint-tool";
  return "inventory-theme-toner";
}
function inventoryBusinessGroupHasDailyStockFlow(value: InventoryBusinessGroup) {
  return value === "SUPPLY";
}
function tonerHistoryEntries(list: MaintenanceEntry[] | undefined) {
  return (Array.isArray(list) ? list : []).filter(
    (entry) =>
      String(entry?.type || "").trim().toLowerCase() === "toner replacement" ||
      Number(entry?.tonerItemId || 0) > 0
  );
}
function isInventoryTxnStockEffective(tx: InventoryTxn) {
  if (isInventoryTxnOut(tx.type) && (tx.approvalStatus === "PENDING" || tx.approvalStatus === "REJECTED")) {
    return false;
  }
  return true;
}
function calcInventoryCurrentStockFromRows(
  item: Pick<InventoryItem, "id" | "openingQty">,
  txns: InventoryTxn[]
) {
  const openingQty = Math.max(0, Number(item.openingQty || 0));
  const rows = txns
    .filter((tx) => Number(tx.itemId) === Number(item.id))
    .slice()
    .sort((a, b) => {
      const aDate = normalizeYmdInput(a.date) || String(a.date || "");
      const bDate = normalizeYmdInput(b.date) || String(b.date || "");
      if (aDate !== bDate) return aDate.localeCompare(bDate);
      return Number(a.id || 0) - Number(b.id || 0);
    });
  let stock = openingQty;
  for (const tx of rows) {
    if (!isInventoryTxnStockEffective(tx)) continue;
    const qty = Math.max(0, Number(tx.qty || 0));
    if (isInventoryTxnSet(tx.type)) {
      stock = qty;
      continue;
    }
    if (isInventoryTxnIn(tx.type)) stock += qty;
    if (isInventoryTxnOut(tx.type)) stock -= qty;
  }
  return stock;
}
function inventoryTxnTypeLabel(type: InventoryTxn["type"]) {
  const row = INVENTORY_TXN_TYPE_OPTIONS.find((option) => option.value === type);
  return row ? row.label : type;
}
function inventoryTxnApprovalLabel(tx: InventoryTxn, lang: Lang) {
  if (!isInventoryTxnUsageOut(tx.type)) return "";
  if (tx.approvalStatus === "PENDING") return lang === "km" ? "រង់ចាំអនុម័ត" : "Pending Approval";
  if (tx.approvalStatus === "REJECTED") return lang === "km" ? "បានបដិសេធ" : "Rejected";
  return "";
}
function inventoryAliasText(itemName: string) {
  const name = String(itemName || "").toLowerCase();
  const hit = INVENTORY_MASTER_ITEMS.find((item) => name.includes(item.nameEn.toLowerCase()));
  return hit ? hit.aliases.join(" ") : "";
}
