function isComputerMaintenanceAsset(asset?: Pick<Asset, "category" | "type"> | null) {
  const category = String(asset?.category || "").trim().toUpperCase();
  const type = String(asset?.type || "").trim().toUpperCase();
  return category === "IT" && (type === "PC" || type === "LAP");
}

function isIpadMaintenanceAsset(asset?: Pick<Asset, "type"> | null) {
  return String(asset?.type || "").trim().toUpperCase() === "TAB";
}

function getMaintenanceTemplateKey(asset?: Pick<Asset, "category" | "type"> | null): MaintenanceTemplateKey {
  if (isAirconAsset(String(asset?.category || ""), String(asset?.type || ""))) return "aircon";
  if (isIpadMaintenanceAsset(asset)) return "ipad";
  if (isComputerMaintenanceAsset(asset)) return "computer";
  return "general";
}

function normalizeMaintenanceWorkflow(input: unknown): MaintenanceWorkflow {
  const source = input && typeof input === "object" ? input as MaintenanceWorkflow : {};
  const template = String(source.template || "").trim().toLowerCase() as MaintenanceTemplateKey;
  const checklist = Array.isArray(source.checklist)
    ? Array.from(new Set(source.checklist.map((item) => String(item || "").trim()).filter(Boolean)))
    : [];
  return {
    template: template === "computer" || template === "aircon" || template === "ipad" ? template : "general",
    requesterName: String(source.requesterName || "").trim(),
    priority: MAINTENANCE_WORKFLOW_PRIORITY_OPTIONS.includes(source.priority || "Normal")
      ? source.priority
      : "Normal",
    issueSummary: String(source.issueSummary || "").trim(),
    startedAt: String(source.startedAt || "").trim(),
    completedAt: String(source.completedAt || "").trim(),
    downtimeHours: String(source.downtimeHours || "").trim(),
    safetyCheck: Boolean(source.safetyCheck),
    userIssueConfirmed: Boolean(source.userIssueConfirmed),
    rootCause: String(source.rootCause || "").trim(),
    workPerformed: String(source.workPerformed || "").trim(),
    partsUsed: String(source.partsUsed || "").trim(),
    toolsUsed: String(source.toolsUsed || "").trim(),
    testResult: String(source.testResult || "").trim(),
    followUp: String(source.followUp || "").trim(),
    userConfirmation: String(source.userConfirmation || "").trim(),
    checklist,
  };
}

function createMaintenanceRecordForm(
  asset?: Asset | null,
  preferredDate = toYmd(new Date()),
  preferredBy = ""
) {
  const workflow = normalizeMaintenanceWorkflow({
    template: getMaintenanceTemplateKey(asset),
    priority: "Normal",
  });
  return {
    assetId: asset ? String(asset.id) : "",
    date: preferredDate,
    type: "Preventive",
    completion: "Done" as "Done" | "Not Yet",
    condition: "",
    note: "",
    cost: "",
    by: String(preferredBy || "").trim(),
    photo: "",
    photos: [] as string[],
    beforePhotos: [] as string[],
    afterPhotos: [] as string[],
    reportFile: null as MaintenanceReportFile | null,
    workflow,
  };
}

function normalizeMaintenanceReportFile(input: unknown): MaintenanceReportFile | null {
  if (!input) return null;
  if (typeof input === "string") {
    const url = String(input || "").trim();
    if (!url) return null;
    return { url, name: "", mimeType: "" };
  }
  if (typeof input === "object") {
    const source = input as Partial<MaintenanceReportFile> & {
      reportFile?: string;
      reportFileName?: string;
      reportFileType?: string;
    };
    const url = String(source.url || source.reportFile || "").trim();
    if (!url) return null;
    return {
      url,
      name: String(source.name || source.reportFileName || "").trim(),
      mimeType: String(source.mimeType || source.reportFileType || "").trim(),
    };
  }
  return null;
}

function maintenanceReportFileLabel(file: MaintenanceReportFile | null | undefined) {
  const normalized = normalizeMaintenanceReportFile(file);
  if (!normalized?.url) return "";
  if (normalized.name) return normalized.name;
  try {
    const parsed = new URL(normalized.url, "http://local");
    const base = parsed.pathname.split("/").filter(Boolean).pop() || "";
    return base || "maintenance-report";
  } catch {
    return normalized.url.split("/").filter(Boolean).pop() || "maintenance-report";
  }
}

function normalizeMaintenanceEntryPhotos(entry: Partial<MaintenanceEntry>) {
  const beforePhotos = normalizeMaintenancePhotoList(entry.beforePhotos);
  const afterBase = normalizeMaintenancePhotoList(entry.afterPhotos);
  const legacyAfter = normalizeMaintenancePhotoList(entry.photos);
  const photo = String(entry.photo || "").trim();
  const afterPhotos = afterBase.length
    ? afterBase
    : legacyAfter.length
      ? legacyAfter
      : normalizeMaintenancePhotoList(photo ? [photo] : []);
  return {
    beforePhotos,
    afterPhotos,
    photo: afterPhotos[0] || "",
    photos: afterPhotos,
  };
}

function normalizeMaintenanceReportFileUrl(file: MaintenanceReportFile | null | undefined) {
  const normalized = normalizeMaintenanceReportFile(file);
  return normalized?.url ? resolveApiResourceUrl(normalized.url) : "";
}

function normalizeAssetSerialKey(value: string) {
  return String(value || "").trim().toUpperCase();
}

function findDuplicateAssetSerial(list: Asset[], serialNumber: string, excludeId?: number) {
  const key = normalizeAssetSerialKey(serialNumber);
  if (!key) return null;
  return (
    list.find(
      (asset) =>
        Number(asset.id) !== Number(excludeId || 0) &&
        normalizeAssetSerialKey(String(asset.serialNumber || "")) === key
    ) || null
  );
}

function isAirconAsset(category: string, type: string) {
  return String(category || "").toUpperCase() === "FACILITY" && String(type || "").toUpperCase() === "AC";
}

function hidesAssignmentHistory(category: string, type: string) {
  const normalizedCategory = String(category || "").trim().toUpperCase();
  const normalizedType = String(type || "").trim().toUpperCase();
  return (
    (normalizedCategory === "FACILITY" && normalizedType === "AC") ||
    (normalizedCategory === "IT" && normalizedType === TV_TYPE_CODE)
  );
}

function showsIncludedComponentCards(category: string, type: string) {
  const normalizedCategory = String(category || "").trim().toUpperCase();
  const normalizedType = String(type || "").trim().toUpperCase();
  return (
    (normalizedCategory === "IT" && normalizedType === TV_TYPE_CODE) ||
    (normalizedCategory === "FACILITY" && normalizedType === "AC")
  );
}

type AirconComponentPhotoKey = "acRemotePhoto" | "acFrontUnitPhoto" | "acOutdoorPhoto";

function airconComponentLabel(type: string) {
  const normalizedType = String(type || "").trim().toUpperCase();
  if (normalizedType === REMOTE_TYPE_CODE) return "Remote";
  if (normalizedType === AIRCON_FRONT_UNIT_TYPE_CODE) return "Front Unit (Indoor)";
  if (normalizedType === AIRCON_OUTDOOR_UNIT_TYPE_CODE) return "Back Unit (Outdoor)";
  return normalizedType;
}

function parseAirconSpecs(specsRaw: string) {
  const specs = String(specsRaw || "").trim();
  if (!specs) {
    return {
      acType: "",
      acHp: "",
      acHasRemote: false,
      acHasFrontPanel: false,
      acHasOutdoor: false,
      acComponentNote: "",
      specs: "",
    };
  }
  let acType = "";
  let acHp = "";
  let acHasRemote = false;
  let acHasFrontPanel = false;
  let acHasOutdoor = false;
  let acComponentNote = "";
  const typeMatch = specs.match(/AC Type:\s*([^|\n;]+?)(?=\s*(?:Capacity:|Included:|Components? Note:|$))/i);
  const hpMatch = specs.match(/Capacity:\s*([^|\n;]+?)(?=\s*(?:Included:|Components? Note:|$))/i);
  const includedMatch = specs.match(/Included:\s*([^|\n;]+?)(?=\s*(?:Components? Note:|$))/i);
  const componentNoteMatch = specs.match(/Components? Note:\s*([^\n|;]+)/i);
  if (typeMatch?.[1]) acType = String(typeMatch[1]).trim();
  if (hpMatch?.[1]) acHp = String(hpMatch[1]).trim();
  if (includedMatch?.[1]) {
    const includedText = String(includedMatch[1]).toLowerCase();
    acHasRemote = includedText.includes("remote");
    acHasFrontPanel = includedText.includes("front panel");
    acHasOutdoor =
      includedText.includes("outdoor unit") ||
      includedText.includes("back unit") ||
      includedText.includes("rear unit");
  } else {
    // Default for legacy AC records: working unit should include both front and outdoor parts.
    acHasFrontPanel = true;
    acHasOutdoor = true;
  }
  if (componentNoteMatch?.[1]) acComponentNote = String(componentNoteMatch[1]).trim();
  const cleanedSpecs = specs
    .replace(/AC Type:\s*([^|\n;]+?)(?=\s*(?:Capacity:|Included:|Components? Note:|$))/gi, "")
    .replace(/Capacity:\s*([^|\n;]+?)(?=\s*(?:Included:|Components? Note:|$))/gi, "")
    .replace(/Included:\s*([^|\n;]+?)(?=\s*(?:Components? Note:|$))/gi, "")
    .replace(/Components? Note:\s*([^\n|;]+)/gi, "")
    .replace(/[|;]+/g, "\n")
    .replace(/\n\s*,/g, "\n")
    .replace(/\n{2,}/g, "\n")
    .replace(/\s{2,}/g, " ")
    .trim();
  return {
    acType,
    acHp,
    acHasRemote,
    acHasFrontPanel,
    acHasOutdoor,
    acComponentNote,
    specs: cleanedSpecs,
  };
}

function buildAirconSpecs(
  baseSpecs: string,
  acType: string,
  acHp: string,
  components?: {
    hasRemote: boolean;
    hasFrontPanel: boolean;
    hasOutdoor: boolean;
    componentNote: string;
  }
) {
  const normalized = parseAirconSpecs(baseSpecs);
  const out: string[] = [];
  const type = String(acType || "").trim();
  const hp = String(acHp || "").trim();
  const hasRemote = components ? Boolean(components.hasRemote) : normalized.acHasRemote;
  const hasFrontPanel = components ? Boolean(components.hasFrontPanel) : normalized.acHasFrontPanel;
  const hasOutdoor = components ? Boolean(components.hasOutdoor) : normalized.acHasOutdoor;
  const componentNote = components ? String(components.componentNote || "").trim() : normalized.acComponentNote;
  if (type) out.push(`AC Type: ${type}`);
  if (hp) out.push(`Capacity: ${hp}`);
  const included: string[] = [];
  if (hasRemote) included.push("Remote");
  if (hasFrontPanel) included.push("Front Panel");
  if (hasOutdoor) included.push("Outdoor Unit");
  if (included.length) out.push(`Included: ${included.join(", ")}`);
  if (componentNote) out.push(`Components Note: ${componentNote}`);
  if (normalized.specs) out.push(normalized.specs);
  return out.join("\n").trim();
}

function parseWalkieTalkieSpecs(specsRaw: string) {
  const specs = String(specsRaw || "").trim();
  if (!specs) {
    return {
      hasCharger: false,
      chargerDetail: "",
      specs: "",
    };
  }
  const includedMatch = specs.match(/Included:\s*([^|\n;]+)/i);
  const includedText = includedMatch?.[1] ? String(includedMatch[1]).toLowerCase() : "";
  const hasCharger = includedText.includes("charger");
  const chargerDetailMatch = specs.match(/Charger\s*(?:Detail|Note):\s*([^\n|;]+)/i);
  const chargerDetail = chargerDetailMatch?.[1] ? String(chargerDetailMatch[1]).trim() : "";
  const cleanedSpecs = specs
    .replace(/Included:\s*([^|\n;]+)/gi, "")
    .replace(/Charger\s*(?:Detail|Note):\s*([^\n|;]+)/gi, "")
    .replace(/[|;]+/g, "\n")
    .replace(/\n{2,}/g, "\n")
    .replace(/\s{2,}/g, " ")
    .trim();
  return {
    hasCharger,
    chargerDetail,
    specs: cleanedSpecs,
  };
}

function buildWalkieTalkieSpecs(baseSpecs: string, hasCharger: boolean, chargerDetail?: string) {
  const normalized = parseWalkieTalkieSpecs(baseSpecs);
  const out: string[] = [];
  const detail = String(chargerDetail || "").trim();
  if (hasCharger) out.push("Included: Charger");
  if (hasCharger && detail) out.push(`Charger Detail: ${detail}`);
  if (normalized.specs) out.push(normalized.specs);
  return out.join("\n").trim();
}

function isFurnitureAsset(category: string) {
  return String(category || "").trim().toUpperCase() === "FURNITURE";
}

function defaultFurnitureTrackingMode(type: string) {
  const normalizedType = String(type || "").trim().toUpperCase();
  return normalizedType === "CAB" ? "Individual" : "Grouped";
}

function defaultFurnitureSubtype(type: string) {
  const normalizedType = String(type || "").trim().toUpperCase();
  if (normalizedType === "CHR") return "Student Chair";
  if (normalizedType === "TBL") return "Student Table";
  if (normalizedType === "DSK") return "Student Deskset";
  if (normalizedType === "CAB") return "Cabinet";
  if (normalizedType === "NBD") return "Nap Bed";
  return "";
}

function furnitureSubtypeLabel(type: string, model: string) {
  const normalizedType = String(type || "").trim().toUpperCase();
  const normalizedModel = String(model || "").trim().toLowerCase();
  if (normalizedType === "CHR" && normalizedModel.includes("adult")) return "Adult Chair";
  if (normalizedType === "TBL" && normalizedModel.includes("adult")) return "Adult Table";
  return defaultFurnitureSubtype(type);
}

function furnitureModelLabel(type: string, model: string) {
  const subtype = furnitureSubtypeLabel(type, model) || "Furniture";
  const normalizedModel = String(model || "").trim();
  if (!normalizedModel) return subtype;
  if (normalizedModel.toLowerCase().startsWith(`${subtype.toLowerCase()} (`)) return normalizedModel;
  return `${subtype} (${normalizedModel})`;
}

function furnitureModelOptions(type: string) {
  return FURNITURE_MODEL_OPTIONS_BY_TYPE[String(type || "").trim().toUpperCase()] || [];
}

function parseFurnitureSpecs(specsRaw: string) {
  const specs = String(specsRaw || "").trim();
  if (!specs) {
    return {
      trackingMode: "Grouped",
      level: "",
      subtype: "",
      modelPhoto: "",
      material: "",
      color: "",
      size: "",
      quantity: "1",
      condition: "",
      specs: "",
    };
  }
  const readLine = (label: string) => {
    const escaped = label.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
    const match = specs.match(new RegExp(`${escaped}:\\s*([^|\\n;]+)`, "i"));
    return match?.[1] ? String(match[1]).trim() : "";
  };
  const cleanedSpecs = specs
    .replace(/Tracking Mode:\s*([^|\n;]+)/gi, "")
    .replace(/Level:\s*([^|\n;]+)/gi, "")
    .replace(/Subtype:\s*([^|\n;]+)/gi, "")
    .replace(/Model Photo:\s*([^|\n;]+)/gi, "")
    .replace(/Material:\s*([^|\n;]+)/gi, "")
    .replace(/Color:\s*([^|\n;]+)/gi, "")
    .replace(/Size:\s*([^|\n;]+)/gi, "")
    .replace(/Quantity:\s*([^|\n;]+)/gi, "")
    .replace(/Condition:\s*([^|\n;]+)/gi, "")
    .replace(/[|;]+/g, "\n")
    .replace(/\n{2,}/g, "\n")
    .replace(/\s{2,}/g, " ")
    .trim();
  return {
    trackingMode: readLine("Tracking Mode") || "Grouped",
    level: readLine("Level"),
    subtype: readLine("Subtype"),
    modelPhoto: readLine("Model Photo"),
    material: readLine("Material"),
    color: readLine("Color"),
    size: readLine("Size"),
    quantity: readLine("Quantity") || "1",
    condition: readLine("Condition"),
    specs: cleanedSpecs,
  };
}

function buildFurnitureSpecs(
  baseSpecs: string,
  fields: {
    trackingMode: string;
    level: string;
    subtype: string;
    modelPhoto: string;
    material: string;
    color: string;
    size: string;
    quantity: string;
    condition: string;
  }
) {
  const normalized = parseFurnitureSpecs(baseSpecs);
  const out: string[] = [];
  const trackingMode = String(fields.trackingMode || "").trim();
  const level = String(fields.level || "").trim();
  const subtype = String(fields.subtype || "").trim();
  const modelPhoto = String(fields.modelPhoto || "").trim();
  const material = String(fields.material || "").trim();
  const color = String(fields.color || "").trim();
  const size = String(fields.size || "").trim();
  const quantity = String(fields.quantity || "").trim();
  const condition = String(fields.condition || "").trim();
  if (trackingMode) out.push(`Tracking Mode: ${trackingMode}`);
  if (level) out.push(`Level: ${level}`);
  if (subtype) out.push(`Subtype: ${subtype}`);
  if (modelPhoto) out.push(`Model Photo: ${modelPhoto}`);
  if (material) out.push(`Material: ${material}`);
  if (color) out.push(`Color: ${color}`);
  if (size) out.push(`Size: ${size}`);
  if (quantity) out.push(`Quantity: ${quantity}`);
  if (condition) out.push(`Condition: ${condition}`);
  if (normalized.specs) out.push(normalized.specs);
  return out.join("\n").trim();
}

function groupedFurnitureTransferMeta(asset?: Asset | null) {
  if (!asset || !isFurnitureAsset(asset.category)) return null;
  const details = parseFurnitureSpecs(asset.specs || "");
  if (String(details.trackingMode || "").trim() !== "Grouped") return null;
  return {
    details,
    quantity: Math.max(1, Number(details.quantity || 1)),
  };
}

function isGroupedFurnitureTransferAsset(asset?: Asset | null) {
  return Boolean(groupedFurnitureTransferMeta(asset));
}

function furnitureAssetQuantity(asset?: Asset | null) {
  if (!asset || !isFurnitureAsset(asset.category)) return null;
  const details = parseFurnitureSpecs(asset.specs || "");
  const quantity = Math.max(1, Number(details.quantity || 1));
  return Number.isFinite(quantity) ? quantity : 1;
}

function furnitureModelPhoto(asset?: Asset | null) {
  if (!asset || !isFurnitureAsset(asset.category)) return "";
  const details = parseFurnitureSpecs(asset.specs || "");
  return String(details.modelPhoto || "").trim();
}

function assetDisplayPhoto(asset?: Asset | null) {
  if (!asset) return "";
  if (isFurnitureAsset(asset.category)) {
    return furnitureModelPhoto(asset) || String(asset.photo || "").trim();
  }
  return String(asset.photo || "").trim();
}

function furnitureVisibleSpecs(specsRaw: string) {
  const details = parseFurnitureSpecs(specsRaw);
  return String(details.specs || "").trim() || "-";
}

function furnitureReferencePhotoFromAssets(assets: Asset[], type: string, model: string) {
  const normalizedType = String(type || "").trim().toUpperCase();
  const normalizedModel = String(model || "").trim().toUpperCase();
  if (!normalizedType || !normalizedModel) return "";
  const match = assets.find((asset) => {
    if (!isFurnitureAsset(asset.category)) return false;
    if (String(asset.type || "").trim().toUpperCase() !== normalizedType) return false;
    if (String(asset.model || "").trim().toUpperCase() !== normalizedModel) return false;
    const details = parseFurnitureSpecs(asset.specs || "");
    return Boolean(String(details.modelPhoto || "").trim() || normalizeAssetPhotos(asset).length);
  });
  if (!match) return "";
  const details = parseFurnitureSpecs(match.specs || "");
  return String(details.modelPhoto || "").trim() || normalizeAssetPhotos(match)[0] || "";
}

function furnitureMasterPhoto(models: FurnitureModelMaster[], type: string, model: string) {
  const normalizedType = String(type || "").trim().toUpperCase();
  const normalizedModel = String(model || "").trim().toUpperCase();
  if (!normalizedType || !normalizedModel) return "";
  const hit = models.find(
    (row) =>
      String(row.type || "").trim().toUpperCase() === normalizedType &&
      String(row.model || "").trim().toUpperCase() === normalizedModel
  );
  return String(hit?.photo || "").trim();
}

function deriveFurnitureModelsFromAssets(assets: Asset[]) {
  const byModel = new Map<string, FurnitureModelMaster>();
  for (const asset of normalizeArray<Asset>(assets)) {
    if (!isFurnitureAsset(asset.category)) continue;
    const type = String(asset.type || "").trim().toUpperCase();
    const model = String(asset.model || "").trim();
    if (!type || !model) continue;
    const key = `${type}::${model.toUpperCase()}`;
    const details = parseFurnitureSpecs(asset.specs || "");
    const photo = String(details.modelPhoto || "").trim() || normalizeAssetPhotos(asset)[0] || "";
    const existing = byModel.get(key);
    if (!existing) {
      byModel.set(key, {
        id: Number(asset.id) || Date.now() + byModel.size + 1,
        type,
        model,
        photo,
        created: String(asset.created || new Date().toISOString()),
      });
      continue;
    }
    if (!String(existing.photo || "").trim() && photo) {
      existing.photo = photo;
    }
  }
  return Array.from(byModel.values()).sort((a, b) =>
    a.type.localeCompare(b.type) || a.model.localeCompare(b.model)
  );
}

function mergeFurnitureModelLists(...lists: FurnitureModelMaster[][]) {
  const merged = new Map<string, FurnitureModelMaster>();
  const baselineRows: FurnitureModelMaster[] = FURNITURE_MODEL_BASELINE_ROWS.map((row, index) => ({
    id: 900000 + index,
    type: row.type,
    model: row.model,
    photo: "",
    created: "",
  }));
  for (const list of [baselineRows, ...lists]) {
    for (const row of normalizeArray<FurnitureModelMaster>(list)) {
      const type = String(row.type || "").trim().toUpperCase();
      const model = String(row.model || "").trim();
      if (!type || !model) continue;
      const key = `${type}::${model.toUpperCase()}`;
      const existing = merged.get(key);
      if (!existing) {
        merged.set(key, {
          id: Number(row.id) || Date.now() + merged.size + 1,
          type,
          model,
          photo: String(row.photo || "").trim(),
          created: String(row.created || new Date().toISOString()),
        });
        continue;
      }
      merged.set(key, {
        ...existing,
        ...row,
        type,
        model,
        photo: String(row.photo || "").trim() || String(existing.photo || "").trim(),
        created: String(row.created || "").trim() || String(existing.created || "").trim() || new Date().toISOString(),
      });
    }
  }
  return Array.from(merged.values()).sort((a, b) => a.type.localeCompare(b.type) || a.model.localeCompare(b.model));
}

function furnitureModelPhotoFallbackFromAssets(assets: Asset[], type: string, model: string) {
  const normalizedType = String(type || "").trim().toUpperCase();
  const normalizedModel = String(model || "").trim().toUpperCase();
  if (!normalizedType) return "";
  const assetPhoto = (asset: Asset) => {
    const details = parseFurnitureSpecs(asset.specs || "");
    return String(details.modelPhoto || "").trim() || normalizeAssetPhotos(asset)[0] || "";
  };
  const sameTypeAssets = normalizeArray<Asset>(assets).filter((asset) => {
    if (!isFurnitureAsset(asset.category)) return false;
    return String(asset.type || "").trim().toUpperCase() === normalizedType;
  });
  const exactMatch = sameTypeAssets.find((asset) => {
    if (String(asset.model || "").trim().toUpperCase() !== normalizedModel) return false;
    return Boolean(assetPhoto(asset));
  });
  if (exactMatch) return assetPhoto(exactMatch);
  if (!normalizedModel) return "";
  const keywordParts = normalizedModel
    .split(/[^A-Z0-9]+/)
    .map((part) => part.trim())
    .filter((part) => part.length >= 3);
  const partialMatch = sameTypeAssets.find((asset) => {
    const assetModel = String(asset.model || "").trim().toUpperCase();
    const photo = assetPhoto(asset);
    if (!photo) return false;
    if (!assetModel) return normalizedType === "NBD";
    return keywordParts.some((part) => assetModel.includes(part));
  });
  if (partialMatch) return assetPhoto(partialMatch);
  const typeFallback = sameTypeAssets.find((asset) => Boolean(assetPhoto(asset)));
  return typeFallback ? assetPhoto(typeFallback) : "";
}

function enrichFurnitureModelsWithAssetPhotos(models: FurnitureModelMaster[], assets: Asset[]) {
  return normalizeArray<FurnitureModelMaster>(models).map((row) => {
    const photo = String(row.photo || "").trim() || furnitureModelPhotoFallbackFromAssets(assets, row.type, row.model);
    return photo === String(row.photo || "").trim() ? row : { ...row, photo };
  });
}

function updateGroupedFurnitureAssetQuantity(asset: Asset, quantity: number) {
  const details = parseFurnitureSpecs(asset.specs || "");
  return {
    ...asset,
    specs: buildFurnitureSpecs(asset.specs || "", {
      trackingMode: details.trackingMode || "Grouped",
      level: details.level || "",
      subtype: details.subtype || defaultFurnitureSubtype(asset.type),
      modelPhoto: details.modelPhoto || "",
      material: details.material || "",
      color: details.color || "",
      size: details.size || "",
      quantity: String(Math.max(1, quantity)),
      condition: details.condition || FURNITURE_CONDITION_OPTIONS[0],
    }),
  };
}

function groupedFurnitureTransferMatchKey(asset: Asset) {
  const details = parseFurnitureSpecs(asset.specs || "");
  return [
    String(asset.category || "").trim().toUpperCase(),
    String(asset.type || "").trim().toUpperCase(),
    String(asset.model || "").trim().toUpperCase(),
    String(details.level || "").trim().toUpperCase(),
    String(details.subtype || "").trim().toUpperCase(),
    String(details.trackingMode || "").trim().toUpperCase(),
  ].join("|");
}

function normalizeAssetForUi(asset: Asset): Asset {
  const photos = normalizeAssetPhotos(asset);
  const normalizeUrl = (raw: string) => {
    const text = String(raw || "").trim();
    if (!text) return "";
    try {
      const parsed = new URL(text);
      if (parsed.pathname.startsWith("/uploads/")) return resolveApiResourceUrl(parsed.pathname);
      return parsed.toString();
    } catch {
      // keep original if not URL
    }
    return resolveApiResourceUrl(text);
  };
  const normalizedPhotos = photos.map(normalizeUrl).filter(Boolean);
  const normalizedMaintenanceHistory = Array.isArray(asset.maintenanceHistory)
    ? asset.maintenanceHistory.map((entry) => ({
        ...entry,
        ...normalizeMaintenanceEntryPhotos(entry || {}),
        workflow: normalizeMaintenanceWorkflow(entry.workflow),
        reportFile: normalizeMaintenanceReportFileUrl({
          url: entry.reportFile || "",
          name: entry.reportFileName || "",
          mimeType: entry.reportFileType || "",
        }),
      }))
    : [];
  const custodyHistory = Array.isArray(asset.custodyHistory) ? asset.custodyHistory : [];
  const custodyStatus =
    asset.custodyStatus === "ASSIGNED" || asset.custodyStatus === "IN_STOCK"
      ? asset.custodyStatus
      : (String(asset.assignedTo || "").trim() ? "ASSIGNED" : "IN_STOCK");
  return {
    ...asset,
    componentRole: String(asset.componentRole || "").trim(),
    componentRequired: Boolean(asset.componentRequired),
    photos: normalizedPhotos,
    photo: normalizeUrl(normalizedPhotos[0] || ""),
    maintenanceHistory: normalizedMaintenanceHistory,
    status: asset.status,
    statusHistory: asset.statusHistory,
    custodyHistory,
    custodyStatus,
  };
}

type AssetPickerProps = {
  value: string;
  assets: Asset[];
  onChange: (assetId: string) => void;
  placeholder?: string;
  disabled?: boolean;
  getLabel: (asset: Asset) => string;
};

function AssetPicker({ value, assets, onChange, placeholder = "Select asset", disabled, getLabel }: AssetPickerProps) {
  const [open, setOpen] = useState(false);
  const [search, setSearch] = useState("");
  const deferredSearch = useDeferredValue(search);
  const wrapRef = useRef<HTMLDivElement | null>(null);
  const prevValueRef = useRef(value);
  const selected = assets.find((a) => String(a.id) === value) || null;

  useEffect(() => {
    if (!open) return;
    const onDocClick = (ev: MouseEvent) => {
      if (!wrapRef.current) return;
      if (!wrapRef.current.contains(ev.target as Node)) {
        setOpen(false);
      }
    };
    const onKeyDown = (ev: KeyboardEvent) => {
      if (ev.key === "Escape") {
        setOpen(false);
      }
    };
    document.addEventListener("mousedown", onDocClick);
    document.addEventListener("keydown", onKeyDown);
    return () => {
      document.removeEventListener("mousedown", onDocClick);
      document.removeEventListener("keydown", onKeyDown);
    };
  }, [open]);

  useEffect(() => {
    if (prevValueRef.current !== value) {
      prevValueRef.current = value;
      setOpen(false);
      setSearch("");
    }
  }, [value]);

  const filtered = useMemo(() => {
    const q = deferredSearch.trim().toLowerCase();
    if (!q) return assets;
    return assets.filter((a) => {
      const label = getLabel(a);
      return `${a.assetId} ${label} ${a.name} ${a.location} ${a.campus} ${a.category} ${a.type}`
        .toLowerCase()
        .includes(q);
    });
  }, [assets, deferredSearch, getLabel]);

  const selectAsset = useCallback(
    (assetId: string) => {
      onChange(assetId);
      setOpen(false);
      setSearch("");
    },
    [onChange]
  );

  return (
    <div className={`asset-picker searchable-dropdown ${disabled ? "asset-picker-disabled" : ""}`} ref={wrapRef}>
      <button
        type="button"
        className="asset-picker-trigger input"
        disabled={disabled}
        onMouseDown={(e) => {
          // Prevent label re-activation from toggling this twice in wrapped form labels.
          e.preventDefault();
        }}
        onClick={() => setOpen(true)}
      >
        {selected ? (
          <span className="asset-picker-selected">
            {selected.photo ? <img loading="lazy" decoding="async" src={selected.photo} alt={selected.assetId} className="asset-picker-thumb" /> : <span className="asset-picker-thumb-empty">-</span>}
            <span>{getLabel(selected)}</span>
          </span>
        ) : (
          <span className="asset-picker-placeholder">{placeholder}</span>
        )}
        <span className="asset-picker-caret">▾</span>
      </button>
      {open ? (
        <div className="asset-picker-menu">
          <input
            className="input asset-picker-search"
            placeholder="Search by ID or name..."
            value={search}
            onChange={(e) => setSearch(e.target.value)}
          />
          <div className="asset-picker-list">
            {filtered.length ? (
              filtered.map((asset) => (
                <button
                  type="button"
                  key={`asset-picker-${asset.id}`}
                  className={`asset-picker-option ${String(asset.id) === value ? "asset-picker-option-active" : ""}`}
                  onMouseDown={(e) => {
                    e.preventDefault();
                    e.stopPropagation();
                    selectAsset(String(asset.id));
                  }}
                  onClick={() => selectAsset(String(asset.id))}
                >
                  {asset.photo ? <img loading="lazy" decoding="async" src={asset.photo} alt={asset.assetId} className="asset-picker-thumb" /> : <span className="asset-picker-thumb-empty">-</span>}
                  <span>{getLabel(asset)}</span>
                </button>
              ))
            ) : (
              <div className="asset-picker-empty">No assets found.</div>
            )}
          </div>
        </div>
      ) : null}
    </div>
  );
}

