    const date = new Date(`${ymd}T00:00:00`);
    if (Number.isNaN(date.getTime())) return inventoryAdminMatrixDateFrom;
    return date.toLocaleDateString("en-GB", {
      day: "2-digit",
      month: "short",
      year: "numeric",
    }).replace(/ /g, "/");
