  async function autofillRentalCounterFromPhoto(photoInput?: string) {
    if (!requireAdminAction()) return;
    const photo = String(photoInput || rentalCounterForm.photo || "").trim();
    if (!photo) {
      setError("Please upload a printer screenshot first.");
      return;
    }
    setRentalCounterAutofillBusy(true);
    setRentalPrinterMessage("");
    try {
      const candidates = await buildPrinterCounterOcrCandidates(photo);
      let extracted: {
        currentMono?: string;
        rawText?: string;
        warnings?: string[];
      } = {};
      let successfulCandidateLabel = "";

      for (const candidate of candidates) {
        const res = await requestJson<{
          ok: boolean;
          extracted?: {
            currentMono?: string;
            rawText?: string;
            warnings?: string[];
          };
        }>("/api/printers/counter-autofill", {
          method: "POST",
          body: JSON.stringify({
            machineCode: selectedRentalPrinter?.machineCode || "",
            photo: candidate.photo,
          }),
        });
        extracted = res.extracted || {};
        if (extracted.currentMono) {
          successfulCandidateLabel = candidate.label;
          break;
        }
      }

      setRentalCounterForm((prev) => ({
        ...prev,
        photo,
        currentMono: extracted.currentMono || prev.currentMono,
        note:
          prev.note ||
          [
            successfulCandidateLabel ? `OCR source: ${successfulCandidateLabel}` : "",
            Array.isArray(extracted.warnings) && extracted.warnings.length
              ? `OCR note: ${extracted.warnings.join(" ")}`
              : "",
          ]
            .filter(Boolean)
            .join(" | "),
      }));
      setRentalPrinterMessage(
        extracted.currentMono
          ? `Printer auto fill completed from ${successfulCandidateLabel || "screenshot"}. Please review the counter before saving.`
          : Array.isArray(extracted.warnings) && extracted.warnings.length
          ? `Printer auto fill completed with checks needed: ${extracted.warnings.join(" ")}`
          : "Printer auto fill completed. Please review the counter before saving."
      );
    } catch (err) {
      setError(err instanceof Error ? err.message : "Printer auto fill failed.");
    } finally {
      setRentalCounterAutofillBusy(false);
    }
  }

  async function readRentalCounterFromPrinterIp() {
    if (!requireAdminAction()) return;
    if (!selectedRentalPrinter?.ipAddress?.trim()) {
      setError("Printer IP / Web Address is required.");
      return;
    }
    setError("");
    setRentalCounterIpReadBusy(true);
    setRentalPrinterMessage("");
    try {
      const res = await requestJson<{
        ok: boolean;
        extracted?: {
          currentMono?: string;
          updatedAt?: string;
          warnings?: string[];
          sourceUrl?: string;
        };
      }>("/api/printers/counter-from-ip", {
        method: "POST",
        body: JSON.stringify({
          machineCode: selectedRentalPrinter.machineCode || "",
          ipAddress: selectedRentalPrinter.ipAddress || "",
          campus: selectedRentalPrinter.campus || "",
        }),
      });
      const extracted = res.extracted || {};
      setRentalCounterForm((prev) => ({
        ...prev,
        currentMono: extracted.currentMono || prev.currentMono,
        note:
          prev.note ||
          [
            extracted.updatedAt ? `Printer page updated: ${extracted.updatedAt}` : "",
            Array.isArray(extracted.warnings) && extracted.warnings.length
              ? `IP read note: ${extracted.warnings.join(" ")}`
              : "",
          ]
            .filter(Boolean)
            .join(" | "),
      }));
      setRentalPrinterMessage(
        extracted.currentMono
          ? `Counter read from printer IP${extracted.updatedAt ? ` (${extracted.updatedAt})` : ""}. Please review before saving.`
          : "Could not detect Total 2 from printer IP. Please review the printer page or use screenshot read."
      );
    } catch (err) {
      const message = err instanceof Error ? err.message : "Printer IP read failed.";
      setError(message);
      setRentalPrinterMessage(
        message.includes("require login")
          ? "Read From Printer IP could not read 102 : Total 2 because the Canon page likely needs login first. Open Printer Web and use screenshot/manual entry for now."
          : `Read From Printer IP failed: ${message}`
      );
    } finally {
      setRentalCounterIpReadBusy(false);
    }
  }

  async function autofillUtilityInvoiceFromPhoto(photoInput?: string) {
    if (!requireAdminAction()) return;
    const photo = String(photoInput || utilityInvoiceForm.photo || "").trim();
    if (!photo) {
      setError("Please upload an invoice image first.");
      return;
    }
    setUtilityAutofillBusy(true);
    setUtilityMessage("");
    try {
      const res = await requestJson<{
        ok: boolean;
        extracted?: {
          usage?: string;
          amount?: string;
          invoiceNumber?: string;
          invoiceDate?: string;
          billingMonth?: string;
          providerName?: string;
          campus?: string;
          location?: string;
          rawText?: string;
          warnings?: string[];
        };
      }>("/api/utilities/invoice-autofill", {
        method: "POST",
        body: JSON.stringify({
          utilityType: utilityInvoiceForm.utilityType,
          photo,
        }),
      });
      const extracted = res.extracted || {};
      const derivedEdcBillingMonth =
        utilityInvoiceForm.utilityType === "EDC" && extracted.invoiceDate
          ? (() => {
              const match = String(extracted.invoiceDate || "").match(/^(\d{4})-(\d{2})-\d{2}$/);
              if (!match) return "";
              const shifted = new Date(Date.UTC(Number(match[1]), Number(match[2]) - 2, 1));
              return `${shifted.getUTCFullYear()}-${String(shifted.getUTCMonth() + 1).padStart(2, "0")}`;
            })()
          : "";
      setUtilityInvoiceForm((prev) => ({
        ...prev,
        photo,
        usage: extracted.usage ? formatNumericInputDisplay(extracted.usage) : prev.usage,
        amount: extracted.amount ? formatNumericInputDisplay(extracted.amount) : prev.amount,
        invoiceNumber: extracted.invoiceNumber || prev.invoiceNumber,
        invoiceDate: extracted.invoiceDate || prev.invoiceDate,
        billingMonth: derivedEdcBillingMonth || extracted.billingMonth || prev.billingMonth,
        providerName: extracted.providerName || prev.providerName,
        campus: extracted.campus || prev.campus,
        location:
          extracted.location !== undefined
            ? extracted.location
            : extracted.campus && extracted.campus !== prev.campus
              ? ""
              : prev.location,
        note:
          prev.note ||
          (Array.isArray(extracted.warnings) && extracted.warnings.length
            ? `OCR note: ${extracted.warnings.join(" ")}`
            : prev.note),
      }));
      setUtilityMessage(
        Array.isArray(extracted.warnings) && extracted.warnings.length
          ? `Invoice auto fill completed with checks needed: ${extracted.warnings.join(" ")}`
          : "Invoice auto fill completed. Please review the values before saving."
      );
    } catch (err) {
      setError(err instanceof Error ? err.message : "Invoice auto fill failed.");
    } finally {
      setUtilityAutofillBusy(false);
    }
  }

  async function saveUtilityInvoiceEntry() {
    if (!requireAdminAction()) return;
    if (!utilityInvoiceForm.billingMonth || !utilityInvoiceForm.invoiceDate) {
      setError("Billing month and invoice date are required.");
      return;
    }
    if (utilityInvoiceForm.usage === "" || utilityInvoiceForm.amount === "") {
      setError("Usage and amount are required.");
      return;
    }
    const usage = Math.max(0, Number(String(utilityInvoiceForm.usage).replace(/,/g, "")) || 0);
    const amount = Math.max(0, Number(String(utilityInvoiceForm.amount).replace(/,/g, "")) || 0);
    const row: UtilityReading = {
      id: Date.now(),
      utilityType: utilityInvoiceForm.utilityType,
      campus: utilityInvoiceForm.campus,
      location: utilityInvoiceForm.location.trim(),
      unit: utilityInvoiceForm.utilityType === "PPWS" ? "m3" : "kWh",
      invoiceDate: utilityInvoiceForm.invoiceDate,
      billingMonth: utilityInvoiceForm.billingMonth,
      usage,
      amount,
      invoiceNumber: utilityInvoiceForm.invoiceNumber.trim(),
      providerName:
        utilityInvoiceForm.providerName.trim() ||
        (utilityInvoiceForm.utilityType === "PPWS"
          ? "Phnom Penh Water Supply Authority"
          : "Electricite du Cambodge"),
      photo: utilityInvoiceForm.photo || "",
      note: utilityInvoiceForm.note.trim(),
      created: new Date().toISOString(),
    };
    const nextReadings = [row, ...utilityReadings].sort((a, b) =>
      `${b.billingMonth}-${b.invoiceDate}`.localeCompare(`${a.billingMonth}-${a.invoiceDate}`)
    );
    setUtilityReadings(nextReadings);
    setUtilityInvoiceForm({
      utilityType: utilityInvoiceForm.utilityType,
      campus: utilityInvoiceForm.campus,
      location: utilityInvoiceForm.location,
      billingMonth: toYmd(new Date()).slice(0, 7),
      invoiceDate: toYmd(new Date()),
      usage: "",
      amount: "",
      invoiceNumber: "",
      providerName:
        utilityInvoiceForm.utilityType === "PPWS"
          ? "Phnom Penh Water Supply Authority"
          : "Electricite du Cambodge",
      note: "",
      photo: "",
    });
    setUtilityMessage(`${row.utilityType} invoice saved for ${row.billingMonth}.`);
    try {
      await saveUtilitySettingsToServer(utilityMeters, nextReadings);
    } catch (err) {
      setError(err instanceof Error ? err.message : "Failed to save utility invoice");
    }
  }

