  async function updateInventoryItem() {
    if (!requireAdminAction() || editingInventoryItemId === null) return;
    const current = inventoryItems.find((item) => item.id === editingInventoryItemId);
    if (!current) {
      setError("Inventory item not found.");
      return;
    }
    const itemName = inventoryItemForm.itemName.trim() || current.itemName;
    const unit = inventoryItemForm.unit.trim() || current.unit || "pcs";
    const itemCode = (inventoryItemForm.itemCode.trim().toUpperCase() || current.itemCode);
    const location = inventoryItemForm.location.trim();
    const openingQty = Number(inventoryItemForm.openingQty || 0);
    const minStock = Number(inventoryItemForm.minStock || 0);
    if (!itemCode || !itemName || !location) {
      setError("Item code, item name, and location are required.");
      return;
    }
    if (!Number.isFinite(openingQty) || openingQty < 0) {
      setError("Opening Qty must be 0 or higher.");
      return;
    }
    if (!Number.isFinite(minStock) || minStock < 0) {
      setError("Min Stock must be 0 or higher.");
      return;
    }
    setBusy(true);
    setError("");
    try {
      const res = await requestJson<{ item: InventoryItem }>(`/api/inventory/items/${editingInventoryItemId}`, {
        method: "PATCH",
        body: JSON.stringify({
          campus: inventoryItemForm.campus,
          category: inventoryItemForm.category,
          itemCode,
          itemName,
          unit,
          location,
          openingQty: Math.max(0, Math.round(openingQty)),
          minStock: Math.max(0, Math.round(minStock)),
          vendor: inventoryItemForm.vendor.trim(),
          notes: inventoryItemForm.notes.trim(),
          photo: inventoryItemForm.photo || "",
        }),
      });
      setInventoryItems((prev) => prev.map((item) => (item.id === res.item.id ? res.item : item)));
      appendUiAudit("UPDATE", "inventory_item", res.item.itemCode, `${res.item.campus} | ${res.item.itemName}`);
      cancelInventoryItemEdit();
      setError("");
    } catch (err) {
      setError(err instanceof Error ? err.message : "Failed to update inventory item");
    } finally {
      setBusy(false);
    }
  }

  async function deleteInventoryItem(row: (typeof inventoryBalanceRows)[number]) {
    if (!requireAdminAction()) return;
    const hasTxnHistory = inventoryTxns.some((tx) => tx.itemId === row.id);
    if (hasTxnHistory) {
      setError("Cannot delete item with transaction history. Delete transactions first.");
      return;
    }
    if (!window.confirm(`Delete item ${row.itemCode} - ${row.itemName}?`)) return;
    setBusy(true);
    setError("");
    try {
      try {
        await requestJson<{ ok: boolean }>(`/api/inventory/items/${row.id}`, { method: "DELETE" });
        setInventoryItems((prev) => prev.filter((item) => item.id !== row.id));
      } catch (err) {
        if (!isMissingRouteError(err)) throw err;
        const nextItems = inventoryItems.filter((item) => item.id !== row.id);
        setInventoryItems(nextItems);
        void persistInventorySettings(nextItems, inventoryTxns);
      }
    } catch (err) {
      setError(err instanceof Error ? err.message : "Failed to delete inventory item");
      setBusy(false);
      return;
    }
    appendUiAudit("DELETE", "inventory_item", row.itemCode, `${row.campus} | ${row.itemName}`);
    setBusy(false);
    setError("");
  }

  async function saveInventoryTxnEntry(values: {
    itemId: string;
    date: string;
    type: InventoryTxn["type"];
    qty: string;
    by: string;
    note: string;
    photo?: string;
    requirePhoto?: boolean;
    fromCampus?: string;
    toCampus?: string;
    expectedReturnDate?: string;
    requestedBy?: string;
    approvedBy?: string;
    receivedBy?: string;
  }): Promise<{ ok: boolean; pendingApproval?: boolean; duplicateSuppressed?: boolean }> {
    const itemId = Number(values.itemId);
    const rawQty = Number(values.qty || 0);
    const qty = Math.max(0, Math.round(rawQty));
    const isSetStock = values.type === "SET";
    if (!itemId || !values.date || !Number.isFinite(rawQty) || (!isSetStock && qty <= 0)) {
      setError("Please select item, date, and quantity.");
      return { ok: false };
    }
    const item = inventoryVisibleItems.find((i) => i.id === itemId);
    if (!item) {
      setError("Item not found.");
      return { ok: false };
    }
    const cleanedPhoto = String(values.photo || "").trim();
    if (values.requirePhoto && isInventoryTxnUsageOut(values.type) && !cleanedPhoto) {
      setError("Please take photo for stock-out record.");
      return { ok: false };
    }
    if (isSetStock && !isSuperAdmin) {
      setError("Only Super Admin can use Set Current Stock.");
      return { ok: false };
    }
    const txDate = normalizeYmdInput(values.date);
    const holiday = txDate ? getHolidayEvent(txDate) : { name: "", type: "" as CalendarEventType | "" };
    const isRedHoliday = Boolean(holiday.name) && isNonWorkingHolidayType(holiday.type);
    const day = txDate ? new Date(`${txDate}T00:00:00`).getDay() : -1;
    const isSunday = day === 0;
    const needsApprovalDay = Boolean(txDate) && (isSunday || isRedHoliday);
    const needsManagerApproval =
      isInventoryTxnUsageOut(values.type) &&
      item.category === "SUPPLY" &&
      !isAdmin &&
      needsApprovalDay;
    const needsNonWorkingCheck =
      isInventoryTxnUsageOut(values.type) &&
      item.category === "SUPPLY" &&
      needsApprovalDay;
    if (needsNonWorkingCheck) {
      if (!String(values.note || "").trim()) {
        setError(lang === "km" ? "ចុងសប្តាហ៍/ថ្ងៃឈប់សម្រាក ត្រូវបញ្ចូលមូលហេតុចេញស្តុក។" : "Weekend/Holiday stock out requires note.");
        return { ok: false };
      }
    }
    const currentStock = calcInventoryCurrentStockFromRows(item, inventoryVisibleTxns);
    if (isInventoryTxnOut(values.type) && qty > currentStock) {
      setError(`Not enough stock. Current: ${currentStock}`);
      return { ok: false };
    }
    if (values.type === "IN" && !isSuperAdmin) {
      const txMonth = String(normalizeYmdInput(values.date) || values.date).slice(0, 7);
      const hasMonthlyRefill = inventoryVisibleTxns.some(
        (tx) =>
          tx.itemId === itemId &&
          tx.type === "IN" &&
          String(normalizeYmdInput(tx.date) || tx.date).slice(0, 7) === txMonth
      );
      if (hasMonthlyRefill) {
        setError("Monthly refill already recorded for this item. Use Borrow Return (In) for cross-campus stock.");
        return { ok: false };
      }
    }
    if (isSetStock) {
      const proceed = window.confirm(
        `Set Current Stock will replace ${item.itemCode} from ${currentStock} to ${qty}. This is correction mode. Continue?`
      );
      if (!proceed) return { ok: false };
    }
    const fromCampus = String(values.fromCampus || "").trim();
    const toCampus = String(values.toCampus || "").trim();
    const expectedReturnDate = String(values.expectedReturnDate || "").trim();
    const requestedBy = String(values.requestedBy || "").trim();
    const approvedBy = String(values.approvedBy || "").trim();
    const receivedBy = String(values.receivedBy || "").trim();
    if (values.type === "BORROW_OUT" || values.type === "BORROW_CONSUME") {
      if (!toCampus || !requestedBy || !approvedBy) {
        setError("Borrow Out/Consume requires destination campus, requested by, and approved by.");
        return { ok: false };
      }
      if (toCampus === item.campus) {
        setError("Destination campus must be different from source campus.");
        return { ok: false };
      }
    }
    if (values.type === "BORROW_IN") {
      if (!fromCampus || !receivedBy) {
        setError("Borrow Return requires source campus and received by.");
        return { ok: false };
      }
      if (fromCampus === item.campus) {
        setError("Source campus must be different from current campus.");
        return { ok: false };
      }
    }
    if (inventoryTxnSaveLockRef.current) {
      setError(lang === "km" ? "កំពុងរក្សាទុក សូមរង់ចាំបន្តិច។" : "Save already in progress. Please wait.");
      return { ok: false };
    }
    const tx: InventoryTxn = {
      id: Date.now(),
      itemId: item.id,
      campus: item.campus,
      itemCode: item.itemCode,
      itemName: item.itemName,
      date: values.date,
      type: values.type,
      qty,
      by: values.by.trim(),
      note: values.note.trim(),
      fromCampus: values.type === "BORROW_IN" ? fromCampus : item.campus,
      toCampus: values.type === "BORROW_OUT" || values.type === "BORROW_CONSUME" ? toCampus : item.campus,
      expectedReturnDate: values.type === "BORROW_OUT" ? expectedReturnDate : "",
      requestedBy,
      approvedBy,
      receivedBy,
      photo: cleanedPhoto,
      borrowStatus:
        values.type === "BORROW_OUT"
          ? "BORROW_OPEN"
          : values.type === "BORROW_IN"
            ? "CLOSED"
            : values.type === "BORROW_CONSUME"
              ? "CONSUMED"
              : undefined,
      approvalStatus: needsManagerApproval ? "PENDING" : "APPROVED",
      approvalRequestedBy: needsManagerApproval ? (authUser?.displayName || authUser?.username || values.by.trim()) : "",
      approvalRequestedAt: needsManagerApproval ? new Date().toISOString() : "",
      approvalDecisionBy: needsManagerApproval ? "" : (authUser?.displayName || authUser?.username || values.by.trim()),
      approvalDecisionAt: needsManagerApproval ? "" : new Date().toISOString(),
      approvalDecisionNote: "",
    };
    inventoryTxnSaveLockRef.current = true;
    setInventoryTxnSaveBusy(true);
    setBusy(true);
    try {
      try {
        const res = await requestJson<{ txn: InventoryTxn; telegramAlertSent?: boolean; duplicateSuppressed?: boolean }>("/api/inventory/txns", {
          method: "POST",
          body: JSON.stringify({
            itemId: item.id,
            date: values.date,
            type: values.type,
            qty,
            by: values.by.trim(),
            note: values.note.trim(),
            fromCampus,
            toCampus,
            expectedReturnDate,
            requestedBy,
            approvedBy,
            receivedBy,
            photo: cleanedPhoto,
            approvalStatus: needsManagerApproval ? "PENDING" : "APPROVED",
            approvalRequestedBy: needsManagerApproval ? (authUser?.displayName || authUser?.username || values.by.trim()) : "",
            approvalRequestedAt: needsManagerApproval ? new Date().toISOString() : "",
            approvalDecisionBy: needsManagerApproval ? "" : (authUser?.displayName || authUser?.username || values.by.trim()),
            approvalDecisionAt: needsManagerApproval ? "" : new Date().toISOString(),
            approvalDecisionNote: "",
          }),
        });
        setInventoryTxns((prev) => [res.txn, ...prev.filter((entry) => entry.id !== res.txn.id)]);
        if (res.duplicateSuppressed) {
          setError(
            lang === "km"
              ? "ប្រតិបត្តិការដូចគ្នាត្រូវបានរក្សាទុករួចហើយ។ ការចុចស្ទួនត្រូវបានមិនអើពើ។"
              : "This stock-out was already saved. Duplicate tap ignored."
          );
        } else if (values.type === "OUT" && res.telegramAlertSent === false) {
          setError(lang === "km" ? "បានកត់ត្រាចេញស្តុក ប៉ុន្តែ Telegram alert មិនបានផ្ញើ។" : "Stock-out saved, but Telegram alert failed to send.");
        } else {
          setError("");
        }
        if (!res.duplicateSuppressed) {
          appendUiAudit("CREATE", "inventory_txn", `${res.txn.itemCode}-${res.txn.id}`, `${res.txn.type} ${res.txn.qty} ${item.unit}`);
        }
        return { ok: true, pendingApproval: needsManagerApproval, duplicateSuppressed: Boolean(res.duplicateSuppressed) };
      } catch (err) {
        if (!isMissingRouteError(err)) throw err;
        const nextTxns = [tx, ...inventoryTxns];
        setInventoryTxns(nextTxns);
        void persistInventorySettings(inventoryItems, nextTxns);
        setError("");
        appendUiAudit("CREATE", "inventory_txn", `${item.itemCode}-${tx.id}`, `${tx.type} ${tx.qty} ${item.unit}`);
        return { ok: true, pendingApproval: needsManagerApproval };
      }
    } catch (err) {
      setError(err instanceof Error ? err.message : "Failed to save inventory transaction");
      return { ok: false };
    } finally {
      inventoryTxnSaveLockRef.current = false;
      setInventoryTxnSaveBusy(false);
      setBusy(false);
    }
  }

