  async function saveInventoryQuickOut() {
    if (!inventoryQuickOutModal) return;
    const modal = inventoryQuickOutModal;
    const forcedToday = toYmd(new Date());
    const txDate = maintenanceQuickMode
      ? (isSuperAdmin ? (normalizeYmdInput(modal.date) || modal.date || forcedToday) : forcedToday)
      : (normalizeYmdInput(modal.date) || modal.date);
    if (!isSuperAdmin && txDate && txDate < todayYmd) {
      setError(lang === "km" ? "មិនអាចជ្រើសថ្ងៃមុនថ្ងៃនេះបានទេ។" : "Cannot select a date before today.");
      return;
    }
    const recorder = authUser?.displayName || authUser?.username || "";
    const reason = modal.note.trim();
    if (!reason) {
      setError(lang === "km" ? "សូមបញ្ចូលមូលហេតុចេញស្តុក។" : "Please enter reason for stock-out.");
      return;
    }
    const saved = await saveInventoryTxnEntry({
      itemId: modal.itemId,
      date: txDate,
      type: "OUT",
      qty: modal.qty,
      by: recorder,
      note: reason,
      photo: modal.photo,
      requirePhoto: true,
    });
    if (!saved.ok) return;
    setInventoryDailyForm((prev) => ({
      ...prev,
      type: "OUT",
      itemId: modal.itemId,
      date: txDate,
      by: recorder || prev.by,
      qty: "",
      note: "",
    }));
    if (maintenanceQuickMode) {
      setMaintenanceStockOutViewDate(txDate);
    }
    closeInventoryQuickOut();
    if (saved.pendingApproval) {
      setError(lang === "km" ? "បានផ្ញើសំណើរចេញស្តុក ទៅអ្នកគ្រប់គ្រងសម្រាប់អនុម័ត។" : "Stock-out request sent to manager for approval.");
    }
  }
  async function setInventoryTxnApproval(tx: InventoryTxn, decision: "APPROVED" | "REJECTED") {
    if (!requireAdminAction()) return;
    const note =
      decision === "REJECTED"
        ? window.prompt(lang === "km" ? "មូលហេតុបដិសេធ" : "Reason for rejection", "") || ""
        : "";
    if (decision === "REJECTED" && !note.trim()) return;
    setBusy(true);
    setError("");
    try {
      const res = await requestJson<{ txn: InventoryTxn }>(`/api/inventory/txns/${tx.id}/approval`, {
        method: "PATCH",
        body: JSON.stringify({ status: decision, note: note.trim() }),
      });
      setInventoryTxns((prev) => prev.map((row) => (row.id === res.txn.id ? res.txn : row)));
    } catch (err) {
      setError(err instanceof Error ? err.message : "Failed to update approval");
    } finally {
      setBusy(false);
    }
  }

  function exportPurchaseRequestCsv() {
    if (!filteredInventoryPurchaseRows.length) {
      alert(lang === "km" ? "មិនមានទិន្នន័យសម្រាប់ Export" : "No purchase summary rows to export.");
      return;
    }
    const headers = [
      "Item Code",
      "Item Name",
      "Campus",
      "Category",
      "Unit",
      "Used Qty (Period)",
      "Current Stock",
      "Min Stock",
      "Suggested Qty",
      "Period",
    ];
    const escapeCsvCell = (value: string | number) => {
      const text = String(value ?? "");
      if (!/[",\n]/.test(text)) return text;
      return `"${text.replace(/"/g, "\"\"")}"`;
    };
    const lines = [
      headers.join(","),
      ...filteredInventoryPurchaseRows.map((row) =>
        [
          row.itemCode,
          row.itemName,
          inventoryCampusLabel(row.campus),
          row.category,
          row.unit,
          row.usedQty,
          row.currentStock,
          row.minStock,
          getPurchaseRequestQty(row),
          inventoryPurchaseWindow.label,
        ]
          .map(escapeCsvCell)
          .join(",")
      ),
    ];
    const blob = new Blob([`\uFEFF${lines.join("\n")}`], { type: "text/csv;charset=utf-8;" });
    const url = URL.createObjectURL(blob);
    const a = document.createElement("a");
    a.href = url;
    a.download = `purchase-request-${inventoryPurchaseWindow.startYmd}-to-${inventoryPurchaseWindow.endYmd}.csv`;
    document.body.appendChild(a);
    a.click();
    a.remove();
    URL.revokeObjectURL(url);
  }

