  async function addMissingProjectorComponents() {
    if (!editingAsset) return;
    if (!requireAdminAction()) return;
    if (!(editingAsset.category === "IT" && editingAsset.type === PROJECTOR_TYPE)) return;

    const missingTypes = projectorComponentMeta
      .map((item) => item.type)
      .filter((type) => !editingProjectorComponentChildren[type]);

    if (!missingTypes.length) {
      alert(t.noMissingComponents);
      return;
    }

    setBusy(true);
    setError("");
    try {
      let createdCount = 0;
      for (const type of missingTypes) {
        await editOrCreateProjectorComponentChild(type, {
          openEditor: false,
          reloadData: false,
          manageBusy: false,
        });
        createdCount += 1;
      }
      await loadData();
      alert(`${t.addedComponents}: ${createdCount}`);
    } catch (err) {
      setError(err instanceof Error ? err.message : "Failed to add missing projector components");
    } finally {
      setBusy(false);
    }
  }

  async function onEditAssetPhotoFile(e: React.ChangeEvent<HTMLInputElement>) {
    const files = Array.from(e.target.files || []);
    if (!files.length) return;
    if (files.some((file) => file.size > 15 * 1024 * 1024)) {
      alert(t.photoLimit);
      e.target.value = "";
      return;
    }
    try {
      const optimized = await Promise.all(files.map((file) => optimizeUploadPhoto(file)));
      setAssetEditForm((f) => {
        const merged = normalizeAssetPhotos({
          photo: f.photo,
          photos: [...(f.photos || []), ...optimized],
        });
        return { ...f, photo: merged[0] || "", photos: merged };
      });
    } catch (err) {
      handlePhotoUploadError(err);
    } finally {
      e.target.value = "";
    }
  }

  async function updateAsset() {
    if (!requireAdminAction()) return;
    if (editingAssetId === null) return;
    if (!assetEditForm.location.trim()) {
      alert(t.locationRequired);
      return;
    }

    const editingAsset = assets.find((a) => a.id === editingAssetId);
    if (
      isAirconAsset(editingAsset?.category || "", editingAsset?.type || "") &&
      (!assetEditForm.acHasFrontPanel || !assetEditForm.acHasOutdoor)
    ) {
      alert("Air-Con requires both Front Unit and Back Unit (Outdoor) components.");
      return;
    }
    const editingIsDesktop =
      !!editingAsset && editingAsset.category === "IT" && editingAsset.type === DESKTOP_PARENT_TYPE;
    const editingIsLinkable =
      !!editingAsset && canLinkToParentAsset(editingAsset.category, editingAsset.type);
    const editingShouldLinkToParent =
      !!editingAsset && !editingIsDesktop && (editingIsLinkable && assetEditForm.useExistingSet);
    const editingIsWalkieAsset =
      !!editingAsset &&
      editingAsset.category === "IT" &&
      String(editingAsset.type || "").trim().toUpperCase() === WALKIE_TALKIE_TYPE_CODE;
    const needsUser =
      !!editingAsset &&
      USER_REQUIRED_TYPES.includes(editingAsset.type) &&
      String(assetEditForm.status || "").trim().toLowerCase() === "active" &&
      !isSharedLocation(assetEditForm.location);
    if (needsUser && !assetEditForm.assignedTo.trim()) {
      alert(t.userRequired);
      return;
    }
    const editAssignedTo =
      String(assetEditForm.status || "").trim().toLowerCase() === "active"
        ? assetEditForm.assignedTo.trim()
        : "";
    if (editingShouldLinkToParent && !assetEditForm.parentAssetId.trim()) {
      alert(t.selectParentAsset);
      return;
    }
    if (editingIsDesktop && !assetEditForm.pcType.trim()) {
      alert(t.pcTypeRequired);
      return;
    }

    const fromStatusForEdit = editingAsset?.status || "Active";
    const statusChangedInEdit = fromStatusForEdit !== assetEditForm.status;
    let statusChangeReason = "";
    let statusChangeBy = "";
    if (statusChangedInEdit) {
      const suggestedReason = "Updated from asset edit";
      const reasonInput = window.prompt(
        `Provide reason for status change (${assetStatusLabel(fromStatusForEdit)} -> ${assetStatusLabel(assetEditForm.status)}):`,
        suggestedReason
      );
      if (reasonInput === null || !reasonInput.trim()) {
        alert(t.statusReasonRequired);
        return;
      }
      const suggestedBy = authUser?.displayName || authUser?.username || "";
      const byInput = window.prompt("Verified By:", suggestedBy);
      if (byInput === null || !byInput.trim()) {
        alert(t.statusVerifiedByRequired);
        return;
      }
      statusChangeReason = reasonInput.trim();
      statusChangeBy = byInput.trim();
    }

    const payload = {
      location: assetEditForm.location.trim(),
      pcType: editingIsDesktop ? assetEditForm.pcType.trim() : "",
      setCode: editingIsDesktop
        ? assetEditForm.setCode.trim()
        : (editingShouldLinkToParent ? assetEditForm.setCode.trim() : ""),
      parentAssetId: editingIsDesktop
        ? ""
        : (editingShouldLinkToParent ? assetEditForm.parentAssetId.trim().toUpperCase() : ""),
      componentRole: needsComponentRole(editingAsset?.type || "") ? assetEditForm.componentRole.trim() : "",
      componentRequired: Boolean(assetEditForm.componentRequired),
      assignedTo: editAssignedTo,
      brand: assetEditForm.brand.trim(),
      model: editingAsset && isFurnitureAsset(editingAsset.category) && isSingleFurnitureType(editingAsset.type) ? "" : assetEditForm.model.trim(),
      serialNumber: assetEditForm.serialNumber.trim(),
      specs: isAirconAsset(editingAsset?.category || "", editingAsset?.type || "")
        ? buildAirconSpecs(assetEditForm.specs.trim(), assetEditForm.acType, assetEditForm.acHp, {
            hasRemote: assetEditForm.acHasRemote,
            hasFrontPanel: assetEditForm.acHasFrontPanel,
            hasOutdoor: assetEditForm.acHasOutdoor,
            componentNote: assetEditForm.acComponentNote,
          })
        : (String(editingAsset?.type || "").trim().toUpperCase() === WALKIE_TALKIE_TYPE_CODE
            ? buildWalkieTalkieSpecs(
                assetEditForm.specs.trim(),
                Boolean(assetEditForm.walkieHasCharger),
                assetEditForm.walkieChargerDetail
              )
            : (isFurnitureAsset(editingAsset?.category || "")
                ? buildFurnitureSpecs(assetEditForm.specs.trim(), {
                    level: "",
                    subtype: assetEditForm.furnitureSubtype,
                    trackingMode: assetEditForm.furnitureTrackingMode,
                    modelPhoto: "",
                    material: assetEditForm.furnitureMaterial,
                    color: assetEditForm.furnitureColor,
                    size: assetEditForm.furnitureSize,
                    quantity: assetEditForm.furnitureQuantity,
                    condition: assetEditForm.furnitureCondition,
                  })
                : assetEditForm.specs.trim())),
      purchaseDate: assetEditForm.purchaseDate.trim(),
      warrantyUntil: assetEditForm.warrantyUntil.trim(),
      vendor: assetEditForm.vendor.trim(),
      notes: assetEditForm.notes.trim(),
      tonerModel: isPrinterAssetRow(editingAsset) ? assetEditForm.tonerModel.trim() : "",
      tonerItemId: isPrinterAssetRow(editingAsset) ? Number(assetEditForm.tonerItemId || 0) : 0,
      tonerMinStock: isPrinterAssetRow(editingAsset) ? Number(assetEditForm.tonerMinStock || 0) : 0,
      tonerExpectedYield: isPrinterAssetRow(editingAsset) ? Number(assetEditForm.tonerExpectedYield || 0) : 0,
      tonerNotes: isPrinterAssetRow(editingAsset) ? assetEditForm.tonerNotes.trim() : "",
      photo: assetEditForm.photo || "",
      photos: normalizeAssetPhotos(assetEditForm),
      status: assetEditForm.status,
      statusChangeReason,
      statusChangeBy,
      fromStatus: fromStatusForEdit,
    };
    const fromUser = String(editingAsset?.assignedTo || "").trim();
    const toUser = String(editAssignedTo || "").trim();
    const assignmentChangedInEdit = fromUser !== toUser;
    const custodyEntryFromEdit: CustodyEntry | null = assignmentChangedInEdit
      ? {
          id: Date.now() + 1,
          date: new Date().toISOString(),
          action: toUser ? "ASSIGN" : "UNASSIGN",
          fromCampus: editingAsset?.campus || "",
          fromLocation: editingAsset?.location || "-",
          toCampus: editingAsset?.campus || "",
          toLocation: payload.location,
          fromUser,
          toUser,
          responsibilityAck: false,
          by: authUser?.displayName || "",
          note: "Assignment changed from asset edit",
        }
      : null;
    const nextCustodyHistoryForEdit = custodyEntryFromEdit
      ? [custodyEntryFromEdit, ...(editingAsset?.custodyHistory || [])]
      : (editingAsset?.custodyHistory || []);
    const nextCustodyStatusForEdit: Asset["custodyStatus"] = toUser ? "ASSIGNED" : "IN_STOCK";
    const duplicateSerial = findDuplicateAssetSerial(assets, payload.serialNumber, editingAssetId);
    if (duplicateSerial) {
      setError(`Serial number already exists: ${duplicateSerial.assetId}`);
      return;
    }

    setBusy(true);
    setError("");
    try {
      let nextLocal = readAssetFallback().map((a) => {
        if (a.id !== editingAssetId) return a;
        const statusChanged = (a.status || "Active") !== payload.status;
        const statusHistory = statusChanged
          ? [
              {
                id: Date.now(),
                date: new Date().toISOString(),
                fromStatus: a.status || "Active",
                toStatus: payload.status,
                reason: statusChangeReason,
                by: statusChangeBy,
              },
              ...(a.statusHistory || []),
            ]
          : a.statusHistory || [];
        const custodyHistory = custodyEntryFromEdit
          ? [custodyEntryFromEdit, ...(a.custodyHistory || [])]
          : (a.custodyHistory || []);
        const normalizedPhotos = normalizeAssetPhotos(payload);
        return {
          ...a,
          ...payload,
          custodyStatus: nextCustodyStatusForEdit,
          custodyHistory,
          photo: normalizedPhotos[0] || "",
          photos: normalizedPhotos,
          statusHistory,
        };
      });
      try {
        await requestJson<{ asset: Asset }>(`/api/assets/${editingAssetId}`, {
          method: "PATCH",
          body: JSON.stringify({
            ...payload,
            custodyStatus: nextCustodyStatusForEdit,
            custodyHistory: nextCustodyHistoryForEdit,
          }),
        });
      } catch (err) {
        if (!isApiUnavailableError(err) && !isMissingRouteError(err)) throw err;
      }
      if (editingIsWalkieAsset && editingAsset?.assetId) {
        const walkieChargerPhotos = Array.from(
          new Set(
            (assetEditForm.walkieChargerPhotos || [])
              .map((entry) => String(entry || "").trim())
              .filter(Boolean)
          )
        ).slice(0, 4);
        const chargerChildren = nextLocal
          .filter(
            (asset) =>
              asset.assetId !== editingAsset.assetId &&
              String(asset.type || "").trim().toUpperCase() === WALKIE_CHARGER_TYPE_CODE &&
              String(asset.parentAssetId || "").trim() === String(editingAsset.assetId || "").trim()
          )
          .sort(
            (a, b) =>
              (Number(a.seq) || 0) - (Number(b.seq) || 0) ||
              String(a.assetId || "").localeCompare(String(b.assetId || ""))
          );
        const activeCharger = chargerChildren[0] || null;
        const extraChargers = chargerChildren.slice(1);
        if (assetEditForm.walkieHasCharger) {
          const chargerNotes =
            String(assetEditForm.walkieChargerDetail || "").trim() ||
            `Auto-created walkie charger for ${editingAsset.assetId}`;
          if (activeCharger) {
            const updatedCharger: Asset = {
              ...activeCharger,
              campus: editingAsset.campus,
              category: "IT",
              type: WALKIE_CHARGER_TYPE_CODE,
              location: payload.location,
              setCode: "",
              parentAssetId: editingAsset.assetId,
              assignedTo: "",
              custodyStatus: "IN_STOCK",
              brand: payload.brand,
              model: "",
              serialNumber: "",
              specs: "",
              purchaseDate: payload.purchaseDate,
              warrantyUntil: payload.warrantyUntil,
              vendor: payload.vendor,
              notes: chargerNotes,
              photo: walkieChargerPhotos[0] || "",
              photos: walkieChargerPhotos,
              status: payload.status,
            };
            nextLocal = nextLocal.map((asset) => (asset.id === activeCharger.id ? updatedCharger : asset));
            try {
              await requestJson<{ asset: Asset }>(`/api/assets/${activeCharger.id}`, {
                method: "PATCH",
                body: JSON.stringify({
                  location: payload.location,
                  parentAssetId: editingAsset.assetId,
                  brand: payload.brand,
                  model: "",
                  serialNumber: "",
                  specs: "",
                  purchaseDate: payload.purchaseDate,
                  warrantyUntil: payload.warrantyUntil,
                  vendor: payload.vendor,
                  notes: chargerNotes,
                  photo: walkieChargerPhotos[0] || "",
                  photos: walkieChargerPhotos,
                  status: payload.status,
                }),
              });
            } catch (err) {
              if (!isApiUnavailableError(err) && !isMissingRouteError(err)) throw err;
            }
          } else {
            try {
              await requestJson<{ asset: Asset }>("/api/assets", {
                method: "POST",
                body: JSON.stringify({
                  campus: editingAsset.campus,
                  category: "IT",
                  type: WALKIE_CHARGER_TYPE_CODE,
                  location: payload.location,
                  setCode: "",
                  parentAssetId: editingAsset.assetId,
                  assignedTo: "",
                  custodyStatus: "IN_STOCK",
                  brand: payload.brand,
                  model: "",
                  serialNumber: "",
                  specs: "",
                  purchaseDate: payload.purchaseDate,
                  warrantyUntil: payload.warrantyUntil,
                  vendor: payload.vendor,
                  notes: chargerNotes,
                  nextMaintenanceDate: "",
                  scheduleNote: "",
                  photo: walkieChargerPhotos[0] || "",
                  photos: walkieChargerPhotos,
                  status: payload.status,
                }),
              });
            } catch (err) {
              if (!isApiUnavailableError(err) && !isMissingRouteError(err)) throw err;
            }
            const childSeq = calcNextSeq(nextLocal, editingAsset.campus, "IT", WALKIE_CHARGER_TYPE_CODE);
            const newCharger: Asset = {
              id: Date.now() + Math.floor(Math.random() * 10000),
              campus: editingAsset.campus,
              category: "IT",
              type: WALKIE_CHARGER_TYPE_CODE,
              pcType: "",
              seq: childSeq,
              assetId: buildAssetId(editingAsset.campus, "IT", WALKIE_CHARGER_TYPE_CODE, childSeq),
              name: assetItemName("IT", WALKIE_CHARGER_TYPE_CODE),
              location: payload.location,
              setCode: "",
              parentAssetId: editingAsset.assetId,
              assignedTo: "",
              custodyStatus: "IN_STOCK",
              brand: payload.brand,
              model: "",
              serialNumber: "",
              specs: "",
              purchaseDate: payload.purchaseDate,
              warrantyUntil: payload.warrantyUntil,
              vendor: payload.vendor,
              notes: chargerNotes,
              nextMaintenanceDate: "",
              nextVerificationDate: "",
              verificationFrequency: "NONE",
              scheduleNote: "",
              repeatMode: "NONE",
              repeatWeekOfMonth: 0,
              repeatWeekday: 0,
              maintenanceHistory: [],
              verificationHistory: [],
              transferHistory: [],
              custodyHistory: [],
              statusHistory: [
                {
                  id: Date.now(),
                  date: new Date().toISOString(),
                  fromStatus: "New",
                  toStatus: payload.status,
                  reason: "Asset created as walkie charger",
                },
              ],
              photo: walkieChargerPhotos[0] || "",
              photos: walkieChargerPhotos,
              status: payload.status,
              created: new Date().toISOString(),
            };
            nextLocal = [newCharger, ...nextLocal];
          }
        } else {
          nextLocal = nextLocal.filter((asset) => !chargerChildren.some((child) => child.id === asset.id));
        }
        const chargerDeleteTargets = assetEditForm.walkieHasCharger ? extraChargers : chargerChildren;
        for (const charger of chargerDeleteTargets) {
          try {
            await requestJson<{ ok: boolean }>(`/api/assets/${charger.id}`, { method: "DELETE" });
          } catch (err) {
            if (!isApiUnavailableError(err) && !isMissingRouteError(err)) throw err;
          }
          nextLocal = nextLocal.filter((asset) => asset.id !== charger.id);
        }
      }
      if (editingAsset && isAirconAsset(editingAsset.category, editingAsset.type) && editingAsset.assetId) {
        const desiredAirconComponents = [
          ...(assetEditForm.acHasRemote
            ? [{
                category: "IT",
                type: REMOTE_TYPE_CODE,
                label: "Remote",
                note: "Auto-created Air-Con remote",
                photo: String(assetEditForm.acRemotePhoto || "").trim(),
              }]
            : []),
          ...(assetEditForm.acHasFrontPanel
            ? [{
                category: "FACILITY",
                type: AIRCON_FRONT_UNIT_TYPE_CODE,
                label: "Front Unit (Indoor)",
                note: "Auto-created Air-Con front unit",
                photo: String(assetEditForm.acFrontUnitPhoto || "").trim(),
              }]
            : []),
          ...(assetEditForm.acHasOutdoor
            ? [{
                category: "FACILITY",
                type: AIRCON_OUTDOOR_UNIT_TYPE_CODE,
                label: "Back Unit (Outdoor)",
                note: "Auto-created Air-Con back unit",
                photo: String(assetEditForm.acOutdoorPhoto || "").trim(),
              }]
            : []),
        ];
        const existingAirconChildren = nextLocal
          .filter(
            (asset) =>
              asset.assetId !== editingAsset.assetId &&
              String(asset.parentAssetId || "").trim() === String(editingAsset.assetId || "").trim() &&
              [REMOTE_TYPE_CODE, AIRCON_FRONT_UNIT_TYPE_CODE, AIRCON_OUTDOOR_UNIT_TYPE_CODE].includes(
                String(asset.type || "").trim().toUpperCase()
              )
          )
          .sort(
            (a, b) =>
              (Number(a.seq) || 0) - (Number(b.seq) || 0) ||
              String(a.assetId || "").localeCompare(String(b.assetId || ""))
          );
        for (const component of desiredAirconComponents) {
          const matches = existingAirconChildren.filter(
            (asset) => String(asset.type || "").trim().toUpperCase() === component.type
          );
          const active = matches[0] || null;
          const extras = matches.slice(1);
          if (active) {
            const updatedComponent: Asset = {
              ...active,
              campus: editingAsset.campus,
              category: component.category,
              type: component.type,
              location: payload.location,
              setCode: "",
              parentAssetId: editingAsset.assetId,
              assignedTo: "",
              custodyStatus: "IN_STOCK",
              brand: payload.brand,
              model: "",
              serialNumber: "",
              specs: "",
              purchaseDate: payload.purchaseDate,
              warrantyUntil: payload.warrantyUntil,
              vendor: payload.vendor,
              notes: `${component.note} for ${editingAsset.assetId}`,
              photo: component.photo || "",
              photos: component.photo ? [component.photo] : [],
              status: payload.status,
            };
            nextLocal = nextLocal.map((asset) => (asset.id === active.id ? updatedComponent : asset));
            try {
              await requestJson<{ asset: Asset }>(`/api/assets/${active.id}`, {
                method: "PATCH",
                body: JSON.stringify({
                  location: payload.location,
                  parentAssetId: editingAsset.assetId,
                  brand: payload.brand,
                  model: "",
                  serialNumber: "",
                  specs: "",
                  purchaseDate: payload.purchaseDate,
                  warrantyUntil: payload.warrantyUntil,
                  vendor: payload.vendor,
                  notes: `${component.note} for ${editingAsset.assetId}`,
                  photo: component.photo || "",
                  photos: component.photo ? [component.photo] : [],
                  status: payload.status,
                }),
              });
            } catch (err) {
              if (!isApiUnavailableError(err) && !isMissingRouteError(err)) throw err;
            }
          } else {
            try {
              await requestJson<{ asset: Asset }>("/api/assets", {
                method: "POST",
                body: JSON.stringify({
                  campus: editingAsset.campus,
                  category: component.category,
                  type: component.type,
                  location: payload.location,
                  setCode: "",
                  parentAssetId: editingAsset.assetId,
                  assignedTo: "",
                  custodyStatus: "IN_STOCK",
                  brand: payload.brand,
                  model: "",
                  serialNumber: "",
                  specs: "",
                  purchaseDate: payload.purchaseDate,
                  warrantyUntil: payload.warrantyUntil,
                  vendor: payload.vendor,
                  notes: `${component.note} for ${editingAsset.assetId}`,
                  nextMaintenanceDate: "",
                  scheduleNote: "",
                  photo: component.photo || "",
                  photos: component.photo ? [component.photo] : [],
                  status: payload.status,
                }),
              });
            } catch (err) {
              if (!isApiUnavailableError(err) && !isMissingRouteError(err)) throw err;
            }
            const childSeq = calcNextSeq(nextLocal, editingAsset.campus, component.category, component.type);
            const newComponent: Asset = {
              id: Date.now() + Math.floor(Math.random() * 10000),
              campus: editingAsset.campus,
              category: component.category,
              type: component.type,
              pcType: "",
              seq: childSeq,
              assetId: buildAssetId(editingAsset.campus, component.category, component.type, childSeq),
              name: airconComponentLabel(component.type),
              location: payload.location,
              setCode: "",
              parentAssetId: editingAsset.assetId,
              assignedTo: "",
              custodyStatus: "IN_STOCK",
              brand: payload.brand,
              model: "",
              serialNumber: "",
              specs: "",
              purchaseDate: payload.purchaseDate,
              warrantyUntil: payload.warrantyUntil,
              vendor: payload.vendor,
              notes: `${component.note} for ${editingAsset.assetId}`,
              nextMaintenanceDate: "",
              nextVerificationDate: "",
              verificationFrequency: "NONE",
              scheduleNote: "",
              repeatMode: "NONE",
              repeatWeekOfMonth: 0,
              repeatWeekday: 0,
              maintenanceHistory: [],
              verificationHistory: [],
              transferHistory: [],
              custodyHistory: [],
              statusHistory: [
                {
                  id: Date.now(),
                  date: new Date().toISOString(),
                  fromStatus: "New",
                  toStatus: payload.status,
                  reason: `Asset created as ${component.label}`,
                },
              ],
              photo: component.photo || "",
              photos: component.photo ? [component.photo] : [],
              status: payload.status,
              created: new Date().toISOString(),
            };
            nextLocal = [newComponent, ...nextLocal];
          }
          for (const extra of extras) {
            try {
              await requestJson<{ ok: boolean }>(`/api/assets/${extra.id}`, { method: "DELETE" });
            } catch (err) {
              if (!isApiUnavailableError(err) && !isMissingRouteError(err)) throw err;
            }
            nextLocal = nextLocal.filter((asset) => asset.id !== extra.id);
          }
        }
        const desiredTypeSet = new Set(desiredAirconComponents.map((component) => component.type));
        const deleteTargets = existingAirconChildren.filter(
          (asset) => !desiredTypeSet.has(String(asset.type || "").trim().toUpperCase())
        );
        for (const component of deleteTargets) {
          try {
            await requestJson<{ ok: boolean }>(`/api/assets/${component.id}`, { method: "DELETE" });
          } catch (err) {
            if (!isApiUnavailableError(err) && !isMissingRouteError(err)) throw err;
          }
          nextLocal = nextLocal.filter((asset) => asset.id !== component.id);
        }
      }

      writeAssetFallback(nextLocal);
      setAssets(nextLocal);
      setStats(buildStatsFromAssets(nextLocal, campusFilter));
      appendUiAudit("UPDATE", "asset", String(editingAssetId), `location=${payload.location}`);
      if (statusChangedInEdit) {
        const changedAsset = nextLocal.find((a) => a.id === editingAssetId);
        const changedAssetId = changedAsset?.assetId || String(editingAssetId);
        alert(
          `Status updated: ${changedAssetId}\n${assetStatusLabel(fromStatusForEdit)} -> ${assetStatusLabel(payload.status)}\nReason: ${statusChangeReason}\nBy: ${statusChangeBy}`
        );
      }
      setEditingAssetId(null);
      await loadData();
    } catch (err) {
      setError(err instanceof Error ? err.message : "Failed to update asset");
    } finally {
      setBusy(false);
    }
  }

  async function saveMaintenanceSchedule() {
    if (!requireAdminAction()) return;
    if (!scheduleForm.assetId) {
      setError("Please select an asset first.");
      return;
    }
    const requiresDate = scheduleForm.repeatMode !== "MONTHLY_WEEKDAY";
    const normalizedDate = requiresDate ? normalizeYmdInput(scheduleForm.date) : "";
    if (requiresDate && !normalizedDate) {
      setError("Please select a valid date (YYYY-MM-DD).");
      return;
    }
    if (requiresDate && normalizedDate < todayYmd) {
      setError("Cannot set schedule to a past date.");
      return;
    }
    const assetId = Number(scheduleForm.assetId);
    if (!assetId) return;

    const payload = {
      nextMaintenanceDate: normalizedDate,
      scheduleNote:
        scheduleForm.repeatMode === "WDP_FILTER_CYCLE"
          ? getWdpFilterCycleNote(Number(scheduleForm.repeatCycleStep || 1))
          : scheduleForm.note.trim(),
      repeatMode: scheduleForm.repeatMode,
      repeatWeekOfMonth:
        scheduleForm.repeatMode === "MONTHLY_WEEKDAY"
          ? Number(scheduleForm.repeatWeekOfMonth)
          : 0,
      repeatWeekday:
        scheduleForm.repeatMode === "MONTHLY_WEEKDAY"
          ? Number(scheduleForm.repeatWeekday)
          : 0,
      repeatCycleStep:
        scheduleForm.repeatMode === "WDP_FILTER_CYCLE"
          ? Number(scheduleForm.repeatCycleStep || 1)
          : 0,
    };

    setBusy(true);
    setError("");
    try {
      let nextLocal = assets.map((asset) =>
        asset.id === assetId ? { ...asset, ...payload } : asset
      );
      try {
        await requestJson<{ asset: Asset }>(`/api/assets/${assetId}`, {
          method: "PATCH",
          body: JSON.stringify(payload),
        });
      } catch (err) {
        if (!isApiUnavailableError(err)) throw err;
      }
      writeAssetFallback(nextLocal);
      setAssets(nextLocal);
      setStats(buildStatsFromAssets(nextLocal, campusFilter));
      appendUiAudit("SCHEDULE_UPDATE", "asset", String(assetId), payload.nextMaintenanceDate || "repeat schedule");
      const savedAsset = nextLocal.find((asset) => asset.id === assetId);
      setSetupMessage(
        `Schedule saved: ${savedAsset?.assetId || assetId} -> ${
          payload.nextMaintenanceDate || `${scheduleForm.repeatMode} (repeat)`
        }`
      );
      setScheduleForm((f) => ({
        ...f,
        note: "",
        date: "",
      }));
      await loadData();
    } catch (err) {
      setError(err instanceof Error ? err.message : "Failed to save schedule");
    } finally {
      setBusy(false);
    }
  }

  function openQuickScheduleCreate(ymd: string) {
    setSelectedCalendarDate(ymd);
    if (!isAdmin) return;
    const dateObj = new Date(`${ymd}T00:00:00`);
    const computedWeekOfMonth = Number.isFinite(dateObj.getTime())
      ? Math.max(1, Math.min(5, Math.floor((dateObj.getDate() - 1) / 7) + 1))
      : 1;
    const computedWeekday = Number.isFinite(dateObj.getTime()) ? dateObj.getDay() : 6;
    setScheduleQuickForm({
      assetId: "",
      date: ymd,
      note: "",
      repeatMode: "NONE",
      repeatWeekOfMonth: computedWeekOfMonth,
      repeatWeekday: computedWeekday,
      repeatCycleStep: 1,
    });
    setScheduleQuickFilterCampus("ALL");
    setScheduleQuickFilterLocation("ALL");
    setScheduleQuickFilterCategory("ALL");
    setScheduleQuickFilterName("ALL");
    setScheduleQuickCreateOpen(true);
  }

