  function openAssetStatusChangeDialog(id: number, status: string) {
    if (!requireAdminAction()) return;
    const current = assets.find((a) => a.id === id);
    if (!current) return;
    const fromStatus = current.status || "Unknown";
    if (fromStatus === status) return;
    setPendingStatusChange({
      assetId: id,
      fromStatus,
      toStatus: status,
      reason: "",
      verifiedBy: authUser?.displayName || authUser?.username || "",
    });
  }

  async function changeAssetStatus(
    id: number,
    status: string,
    reason = "",
    verifiedBy = ""
  ): Promise<boolean> {
    if (!requireAdminAction()) return false;
    setBusy(true);
    setError("");
    try {
      const current = assets.find((a) => a.id === id);
      const shouldClearAssignedTo = String(status || "").trim().toLowerCase() === "inactive";
      const nextStatusEntry: StatusEntry = {
        id: Date.now(),
        date: new Date().toISOString(),
        fromStatus: current?.status || "Unknown",
        toStatus: status,
        reason,
        by: verifiedBy,
      };
      try {
        await requestJson<{ asset: Asset }>(`/api/assets/${id}/status`, {
          method: "PATCH",
          body: JSON.stringify({
            status,
            fromStatus: current?.status || "Unknown",
            reason,
            by: verifiedBy,
            statusHistory: [nextStatusEntry, ...((current?.statusHistory) || [])],
          }),
        });
      } catch (err) {
        if (!isApiUnavailableError(err) && !isMissingRouteError(err)) throw err;
      }
      if (shouldClearAssignedTo) {
        try {
          await requestJson<{ asset: Asset }>(`/api/assets/${id}`, {
            method: "PATCH",
            body: JSON.stringify({
              assignedTo: "",
            }),
          });
        } catch (err) {
          if (!isApiUnavailableError(err) && !isMissingRouteError(err)) throw err;
        }
      }
      const nextLocal = readAssetFallback().map((asset) =>
          asset.id === id
            ? {
                ...asset,
                status,
                assignedTo: shouldClearAssignedTo ? "" : asset.assignedTo,
                custodyStatus: shouldClearAssignedTo ? "IN_STOCK" : asset.custodyStatus,
                statusHistory: [nextStatusEntry, ...(asset.statusHistory || [])],
              }
            : asset
        );
      writeAssetFallback(nextLocal);
      setAssets(nextLocal);
      setStats(buildStatsFromAssets(nextLocal, campusFilter));
      const fromStatus = nextStatusEntry.fromStatus || "Unknown";
      appendUiAudit(
        "UPDATE_STATUS",
        "asset",
        String(id),
        `${assetStatusLabel(fromStatus)} -> ${assetStatusLabel(status)} | ${reason} | ${verifiedBy}`
      );
      const assetCode = current?.assetId || String(id);
      alert(
        `Status updated: ${assetCode}\n${assetStatusLabel(fromStatus)} -> ${assetStatusLabel(status)}\nReason: ${reason}\nBy: ${verifiedBy}`
      );
      await loadData();
      return true;
    } catch (err) {
      setError(err instanceof Error ? err.message : "Failed to update asset status");
      return false;
    } finally {
      setBusy(false);
    }
  }

  async function changeTicketStatus(id: number, status: string) {
    if (!requireAdminAction()) return;
    setBusy(true);
    setError("");
    try {
      await requestJson<{ ticket: Ticket }>(`/api/tickets/${id}/status`, {
        method: "PATCH",
        body: JSON.stringify({ status }),
      });
      await loadData();
    } catch (err) {
      setError(err instanceof Error ? err.message : "Failed to update ticket status");
    } finally {
      setBusy(false);
    }
  }

  async function onPhotoFile(e: React.ChangeEvent<HTMLInputElement>) {
    const files = Array.from(e.target.files || []);
    if (!files.length) return;
    if (files.some((file) => file.size > 15 * 1024 * 1024)) {
      alert(t.photoLimit);
      e.target.value = "";
      return;
    }
    try {
      const optimized = await Promise.all(files.map((file) => optimizeUploadPhoto(file)));
      setAssetForm((f) => {
        const merged = normalizeAssetPhotos({
          photo: f.photo,
          photos: [...(f.photos || []), ...optimized],
        });
        return { ...f, photo: merged[0] || "", photos: merged };
      });
    } catch (err) {
      handlePhotoUploadError(err);
    } finally {
      e.target.value = "";
    }
  }

