  async function submitPublicQrRepairRequest(asset: PublicQrAsset) {
    if (!asset?.assetId) {
      setPublicQrRecordError("Asset is invalid.");
      return;
    }
    if (!publicQrRequestForm.requestedBy.trim()) {
      setPublicQrRecordError("Requester name is required.");
      return;
    }
    setPublicQrRecordBusy(true);
    setPublicQrRecordError("");
    setPublicQrRecordMessage("");
    try {
      const title = publicQrRequestForm.title.trim() || `Repair request for ${asset.assetId}`;
      await requestJson<{ ticket: Ticket }>("/api/public/tickets", {
        method: "POST",
        body: JSON.stringify({
          assetId: asset.assetId,
          campus: asset.campus,
          category: asset.category,
          title,
          description: publicQrRequestForm.description.trim(),
          requestedBy: publicQrRequestForm.requestedBy.trim(),
          requesterContact: publicQrRequestForm.requesterContact.trim(),
          priority: publicQrRequestForm.priority,
          requestSource: "qr_asset",
          photo: publicQrRequestForm.photo || "",
        }),
      });
      setPublicQrRequestForm({
        title: "",
        description: "",
        requestedBy: "",
        requesterContact: "",
        priority: "Normal",
        photo: "",
      });
      setPublicQrRequestFileKey((k) => k + 1);
      setPublicQrSectionsOpen((prev) => ({ ...prev, request: false }));
      setPublicQrRecordMessage("Work order created. The maintenance team can now follow up this asset.");
    } catch (err) {
      setPublicQrRecordError(err instanceof Error ? err.message : "Failed to create work order");
    } finally {
      setPublicQrRecordBusy(false);
    }
  }

  async function addMaintenanceRecordFromPublicQr(asset: PublicQrAsset) {
    if (!asset?.id) {
      setPublicQrRecordError("Asset ID is invalid.");
      return;
    }
    if (!publicQrRecordForm.date || !publicQrRecordForm.type.trim() || !publicQrRecordForm.note.trim()) {
      setPublicQrRecordError("Date, type, and note are required.");
      return;
    }
    if (publicQrRecordForm.date < todayYmd) {
      setPublicQrRecordError("Cannot set maintenance date to a past date.");
      return;
    }
    setPublicQrRecordBusy(true);
    setPublicQrRecordError("");
    setPublicQrRecordMessage("");
    try {
      await requestJson<{ entry: MaintenanceEntry }>(`/api/assets/${asset.id}/history`, {
        method: "POST",
        body: JSON.stringify({
          date: publicQrRecordForm.date,
          type: publicQrRecordForm.type.trim(),
          completion: publicQrRecordForm.completion,
          condition: publicQrRecordForm.condition.trim(),
          note: publicQrRecordForm.note.trim(),
          cost: publicQrRecordForm.cost.trim(),
          by: publicQrRecordForm.by.trim(),
          photo: publicQrRecordForm.photo || "",
        }),
      });
      const ts = Date.now();
      const refreshed = await requestJson<{ asset: PublicQrAsset }>(
        `/api/public/assets/${encodeURIComponent(asset.assetId)}?ts=${ts}`
      );
      setPublicQrAsset(refreshed.asset || null);
      setPublicQrRecordForm({
        date: toYmd(new Date()),
        type: "Preventive",
        completion: "Done",
        condition: "",
        note: "",
        cost: "",
        by: authUser?.displayName || "",
        photo: "",
      });
      setPublicQrRecordFileKey((k) => k + 1);
      setPublicQrSectionsOpen((prev) => ({ ...prev, maintenance: false }));
      setPublicQrRecordMessage("Maintenance record saved.");
    } catch (err) {
      setPublicQrRecordError(err instanceof Error ? err.message : "Failed to save maintenance record");
    } finally {
      setPublicQrRecordBusy(false);
    }
  }

  async function addTonerRecordFromPublicQr(asset: PublicQrAsset) {
    setPublicQrRecordBusy(true);
    const ok = await saveTonerChangeForAsset(
      asset,
      publicQrTonerForm,
      {
        setForm: setPublicQrTonerForm,
        resetFileKey: () => setPublicQrTonerFileKey((k) => k + 1),
        setMessage: setPublicQrRecordMessage,
        setFormError: setPublicQrRecordError,
        onDone: (savedAsset) => setPublicQrAsset((savedAsset as unknown as PublicQrAsset)),
      }
    );
    setPublicQrRecordBusy(false);
    if (ok) {
      setPublicQrSectionsOpen((prev) => ({ ...prev, toner: false }));
    }
  }

