                                                  const next = [...normalizeAssetPhotos(prev[item.type]).slice(0, MAX_SET_PACK_PHOTOS)];
                                                  const hit = next.indexOf(url);
                                                  if (hit <= 0) return prev;
                                                  next.splice(hit, 1);
                                                  next.unshift(url);
                                                  return {
                                                    ...prev,
                                                    [item.type]: {
                                                      ...prev[item.type],
                                                      photo: next[0] || "",
                                                      photos: next,
                                                    },
                                                  };
